#[inline]
fn eq_ascii_command(lhs: &[u8], rhs: &[u8]) -> bool {
    lhs.len() == rhs.len()
        && lhs
            .iter()
            .zip(rhs.iter())
            .all(|(left, right)| left.to_ascii_uppercase() == *right)
}

fn ping(argv: &[Vec<u8>]) -> Result<RespFrame, CommandError> {
    match argv.len() {
        1 => Ok(RespFrame::SimpleString("PONG".to_string())),
        2 => Ok(RespFrame::BulkString(Some(argv[1].clone()))),
        _ => Err(CommandError::WrongArity("PING")),
    }
}

fn echo(argv: &[Vec<u8>]) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("ECHO"));
    }
    Ok(RespFrame::BulkString(Some(argv[1].clone())))
}

fn set(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("SET"));
    }

    // Expiry mode: at most one of EX/PX/EXAT/PXAT/KEEPTTL
    enum ExpiryMode {
        None,
        Px(u64),
        Ex(u64),
        Pxat(u64),
        Exat(u64),
        KeepTtl,
    }
    let mut expiry_mode = ExpiryMode::None;
    let mut nx = false;
    let mut xx = false;
    let mut get = false;

    let mut options = argv[3..].iter();
    while let Some(option_arg) = options.next() {
        let option =
            std::str::from_utf8(option_arg).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if option.eq_ignore_ascii_case("PX") {
            if !matches!(expiry_mode, ExpiryMode::None) {
                return Err(CommandError::SyntaxError);
            }
            let Some(ttl_arg) = options.next() else {
                return Err(CommandError::SyntaxError);
            };
            expiry_mode = ExpiryMode::Px(parse_set_expire_arg(ttl_arg)?);
        } else if option.eq_ignore_ascii_case("EX") {
            if !matches!(expiry_mode, ExpiryMode::None) {
                return Err(CommandError::SyntaxError);
            }
            let Some(seconds_arg) = options.next() else {
                return Err(CommandError::SyntaxError);
            };
            expiry_mode = ExpiryMode::Ex(parse_set_expire_arg(seconds_arg)?);
        } else if option.eq_ignore_ascii_case("PXAT") {
            if !matches!(expiry_mode, ExpiryMode::None) {
                return Err(CommandError::SyntaxError);
            }
            let Some(ts_arg) = options.next() else {
                return Err(CommandError::SyntaxError);
            };
            expiry_mode = ExpiryMode::Pxat(parse_set_expire_arg(ts_arg)?);
        } else if option.eq_ignore_ascii_case("EXAT") {
            if !matches!(expiry_mode, ExpiryMode::None) {
                return Err(CommandError::SyntaxError);
            }
            let Some(ts_arg) = options.next() else {
                return Err(CommandError::SyntaxError);
            };
            expiry_mode = ExpiryMode::Exat(parse_set_expire_arg(ts_arg)?);
        } else if option.eq_ignore_ascii_case("KEEPTTL") {
            if !matches!(expiry_mode, ExpiryMode::None) {
                return Err(CommandError::SyntaxError);
            }
            expiry_mode = ExpiryMode::KeepTtl;
        } else if option.eq_ignore_ascii_case("NX") {
            nx = true;
        } else if option.eq_ignore_ascii_case("XX") {
            xx = true;
        } else if option.eq_ignore_ascii_case("GET") {
            get = true;
        } else {
            return Err(CommandError::SyntaxError);
        }
    }

    if nx && xx {
        return Err(CommandError::SyntaxError);
    }

    let old_value = if get {
        store.get(&argv[1], now_ms)?
    } else {
        None
    };

    let key_exists = if get {
        old_value.is_some()
    } else {
        store.exists_no_touch(&argv[1], now_ms)
    };
    if nx && key_exists {
        return Ok(if get {
            RespFrame::BulkString(old_value)
        } else {
            RespFrame::BulkString(None)
        });
    }
    if xx && !key_exists {
        return Ok(RespFrame::BulkString(None));
    }

    match expiry_mode {
        ExpiryMode::None => {
            store.set(argv[1].clone(), argv[2].clone(), None, now_ms);
        }
        ExpiryMode::Px(ms) => {
            store.set(argv[1].clone(), argv[2].clone(), Some(ms), now_ms);
        }
        ExpiryMode::Ex(sec) => {
            store.set(
                argv[1].clone(),
                argv[2].clone(),
                Some(sec.saturating_mul(1000)),
                now_ms,
            );
        }
        ExpiryMode::Pxat(abs_ms) => {
            store.set_with_abs_expiry(argv[1].clone(), argv[2].clone(), Some(abs_ms), now_ms);
        }
        ExpiryMode::Exat(abs_sec) => {
            store.set_with_abs_expiry(
                argv[1].clone(),
                argv[2].clone(),
                Some(abs_sec.saturating_mul(1000)),
                now_ms,
            );
        }
        ExpiryMode::KeepTtl => {
            let existing_expiry = store.get_expires_at_ms(&argv[1], now_ms);
            store.set_with_abs_expiry(argv[1].clone(), argv[2].clone(), existing_expiry, now_ms);
        }
    }

    if get {
        Ok(RespFrame::BulkString(old_value))
    } else {
        Ok(RespFrame::SimpleString("OK".to_string()))
    }
}

fn get(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("GET"));
    }
    Ok(RespFrame::BulkString(store.get(&argv[1], now_ms)?))
}

fn delete_keys(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
    command_name: &'static str,
) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity(command_name));
    }
    let removed = store.del(&argv[1..], now_ms);
    let removed = i64::try_from(removed).unwrap_or(i64::MAX);
    Ok(RespFrame::Integer(removed))
}

fn incr(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("INCR"));
    }
    let value = store.incr(&argv[1], now_ms)?;
    Ok(RespFrame::Integer(value))
}

#[derive(Debug, Clone, Copy, Default)]
struct ExpireOptions {
    nx: bool,
    xx: bool,
    gt: bool,
    lt: bool,
}

#[derive(Debug, Clone, Copy)]
enum ExpireCommandKind {
    RelativeSeconds,
    RelativeMilliseconds,
    AbsoluteSeconds,
    AbsoluteMilliseconds,
}

fn expire(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    expire_like(
        argv,
        store,
        now_ms,
        ExpireCommandKind::RelativeSeconds,
        "EXPIRE",
    )
}

fn pexpire(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    expire_like(
        argv,
        store,
        now_ms,
        ExpireCommandKind::RelativeMilliseconds,
        "PEXPIRE",
    )
}

fn expireat(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    expire_like(
        argv,
        store,
        now_ms,
        ExpireCommandKind::AbsoluteSeconds,
        "EXPIREAT",
    )
}

fn pexpireat(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    expire_like(
        argv,
        store,
        now_ms,
        ExpireCommandKind::AbsoluteMilliseconds,
        "PEXPIREAT",
    )
}

fn expire_like(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
    kind: ExpireCommandKind,
    command_name: &'static str,
) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity(command_name));
    }
    let raw_time = parse_i64_arg(&argv[2])?;
    let options = parse_expire_options(&argv[3..])?;
    let when_ms = deadline_from_expire_kind(kind, raw_time, now_ms);
    let applied = apply_expiry_with_options(store, &argv[1], when_ms, now_ms, options);
    Ok(RespFrame::Integer(if applied { 1 } else { 0 }))
}

fn pttl(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("PTTL"));
    }
    let value = match store.pttl(&argv[1], now_ms) {
        PttlValue::KeyMissing => -2,
        PttlValue::NoExpiry => -1,
        PttlValue::Remaining(ms) => ms,
    };
    Ok(RespFrame::Integer(value))
}

fn append(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("APPEND"));
    }
    let current_len = store.strlen(&argv[1], now_ms)?;
    let added_len = argv[2].len();
    if current_len.saturating_add(added_len) > 536_870_912 {
        return Ok(RespFrame::Error(
            "ERR string exceeds maximum allowed size (512MB)".to_string(),
        ));
    }
    let new_len = store.append(&argv[1], &argv[2], now_ms)?;
    let new_len = i64::try_from(new_len).unwrap_or(i64::MAX);
    Ok(RespFrame::Integer(new_len))
}

fn strlen(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("STRLEN"));
    }
    let len = store.strlen(&argv[1], now_ms)?;
    let len = i64::try_from(len).unwrap_or(i64::MAX);
    Ok(RespFrame::Integer(len))
}

fn mget(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("MGET"));
    }
    let keys: Vec<&[u8]> = argv[1..].iter().map(Vec::as_slice).collect();
    let values = store.mget(&keys, now_ms);
    let frames = values.into_iter().map(RespFrame::BulkString).collect();
    Ok(RespFrame::Array(Some(frames)))
}

fn mset(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 || !(argv.len() - 1).is_multiple_of(2) {
        return Err(CommandError::WrongArity("MSET"));
    }
    let mut i = 1;
    while i < argv.len() {
        store.set(argv[i].clone(), argv[i + 1].clone(), None, now_ms);
        i += 2;
    }
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn setnx(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("SETNX"));
    }
    let result = store.setnx(argv[1].clone(), argv[2].clone(), now_ms);
    Ok(RespFrame::Integer(if result { 1 } else { 0 }))
}

fn getset(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("GETSET"));
    }
    let old = store.getset(argv[1].clone(), argv[2].clone(), now_ms)?;
    Ok(RespFrame::BulkString(old))
}

fn incrby(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("INCRBY"));
    }
    let delta = parse_i64_arg(&argv[2])?;
    let value = store.incrby(&argv[1], delta, now_ms)?;
    Ok(RespFrame::Integer(value))
}

fn decrby(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("DECRBY"));
    }
    let delta = parse_i64_arg(&argv[2])?;
    let neg_delta = delta
        .checked_neg()
        .ok_or(CommandError::Store(StoreError::IntegerOverflow))?;
    let value = store.incrby(&argv[1], neg_delta, now_ms)?;
    Ok(RespFrame::Integer(value))
}

fn decr(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("DECR"));
    }
    let value = store.incrby(&argv[1], -1, now_ms)?;
    Ok(RespFrame::Integer(value))
}

fn exists(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("EXISTS"));
    }
    let mut count = 0_i64;
    for key in &argv[1..] {
        if store.exists(key, now_ms) {
            count = count.saturating_add(1);
        }
    }
    Ok(RespFrame::Integer(count))
}

fn ttl(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("TTL"));
    }
    let value = match store.pttl(&argv[1], now_ms) {
        PttlValue::KeyMissing => -2,
        PttlValue::NoExpiry => -1,
        PttlValue::Remaining(ms) => ms / 1000,
    };
    Ok(RespFrame::Integer(value))
}

fn expiretime(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("EXPIRETIME"));
    }
    let value = match store.expiretime_value(&argv[1], now_ms) {
        ExpireTimeValue::KeyMissing => -2,
        ExpireTimeValue::NoExpiry => -1,
        ExpireTimeValue::ExpiresAt(abs_ms) => (abs_ms.saturating_add(500) / 1000) as i64,
    };
    Ok(RespFrame::Integer(value))
}

fn pexpiretime(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("PEXPIRETIME"));
    }
    let value = match store.expiretime_value(&argv[1], now_ms) {
        ExpireTimeValue::KeyMissing => -2,
        ExpireTimeValue::NoExpiry => -1,
        ExpireTimeValue::ExpiresAt(abs_ms) => abs_ms as i64,
    };
    Ok(RespFrame::Integer(value))
}

fn persist(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("PERSIST"));
    }
    let removed = store.persist(&argv[1], now_ms);
    Ok(RespFrame::Integer(if removed { 1 } else { 0 }))
}

fn type_cmd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("TYPE"));
    }
    let type_str = store.key_type(&argv[1], now_ms).unwrap_or("none");
    Ok(RespFrame::SimpleString(type_str.to_string()))
}

fn rename(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("RENAME"));
    }
    store
        .rename(&argv[1], &argv[2], now_ms)
        .map_err(|e| match e {
            StoreError::KeyNotFound => CommandError::NoSuchKey,
            other => CommandError::Store(other),
        })?;
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn renamenx(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("RENAMENX"));
    }
    let result = store
        .renamenx(&argv[1], &argv[2], now_ms)
        .map_err(|e| match e {
            StoreError::KeyNotFound => CommandError::NoSuchKey,
            other => CommandError::Store(other),
        })?;
    Ok(RespFrame::Integer(if result { 1 } else { 0 }))
}

fn keys(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("KEYS"));
    }
    let matched = store.keys_matching(&argv[1], now_ms);
    let frames = matched
        .into_iter()
        .map(|k| RespFrame::BulkString(Some(k)))
        .collect();
    Ok(RespFrame::Array(Some(frames)))
}

fn dbsize(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 1 {
        return Err(CommandError::WrongArity("DBSIZE"));
    }
    let size = store.dbsize(now_ms);
    let size = i64::try_from(size).unwrap_or(i64::MAX);
    Ok(RespFrame::Integer(size))
}

fn flushdb(argv: &[Vec<u8>], store: &mut Store) -> Result<RespFrame, CommandError> {
    if argv.len() > 2 {
        return Err(CommandError::WrongArity("FLUSHDB"));
    }
    store.flushdb();
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn flushall(argv: &[Vec<u8>], store: &mut Store) -> Result<RespFrame, CommandError> {
    if argv.len() > 2 {
        return Err(CommandError::WrongArity("FLUSHALL"));
    }
    store.flushdb();
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn hset(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 4 || !(argv.len() - 2).is_multiple_of(2) {
        return Err(CommandError::WrongArity("HSET"));
    }
    let mut added = 0_usize;
    let mut i = 2;
    while i + 1 < argv.len() {
        if store.hset(&argv[1], argv[i].clone(), argv[i + 1].clone(), now_ms)? {
            added += 1;
        }
        i += 2;
    }
    Ok(RespFrame::Integer(i64::try_from(added).unwrap_or(i64::MAX)))
}

fn hget(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("HGET"));
    }
    let value = store.hget(&argv[1], &argv[2], now_ms)?;
    Ok(RespFrame::BulkString(value))
}

fn hdel(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("HDEL"));
    }
    let fields: Vec<&[u8]> = argv[2..].iter().map(Vec::as_slice).collect();
    let removed = store.hdel(&argv[1], &fields, now_ms)?;
    Ok(RespFrame::Integer(
        i64::try_from(removed).unwrap_or(i64::MAX),
    ))
}

fn hexists(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("HEXISTS"));
    }
    let exists = store.hexists(&argv[1], &argv[2], now_ms)?;
    Ok(RespFrame::Integer(if exists { 1 } else { 0 }))
}

fn hlen(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("HLEN"));
    }
    let len = store.hlen(&argv[1], now_ms)?;
    Ok(RespFrame::Integer(i64::try_from(len).unwrap_or(i64::MAX)))
}

#[allow(clippy::type_complexity)]
fn hgetall(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("HGETALL"));
    }
    let pairs = store.hgetall(&argv[1], now_ms)?;
    let mut frames = Vec::with_capacity(pairs.len() * 2);
    for (field, value) in pairs {
        frames.push(RespFrame::BulkString(Some(field)));
        frames.push(RespFrame::BulkString(Some(value)));
    }
    Ok(RespFrame::Array(Some(frames)))
}

fn hkeys(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("HKEYS"));
    }
    let keys = store.hkeys(&argv[1], now_ms)?;
    let frames = keys
        .into_iter()
        .map(|k| RespFrame::BulkString(Some(k)))
        .collect();
    Ok(RespFrame::Array(Some(frames)))
}

fn hvals(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("HVALS"));
    }
    let vals = store.hvals(&argv[1], now_ms)?;
    let frames = vals
        .into_iter()
        .map(|v| RespFrame::BulkString(Some(v)))
        .collect();
    Ok(RespFrame::Array(Some(frames)))
}

fn hmget(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("HMGET"));
    }
    let fields: Vec<&[u8]> = argv[2..].iter().map(Vec::as_slice).collect();
    let values = store.hmget(&argv[1], &fields, now_ms)?;
    let frames = values.into_iter().map(RespFrame::BulkString).collect();
    Ok(RespFrame::Array(Some(frames)))
}

fn hmset(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 4 || !(argv.len() - 2).is_multiple_of(2) {
        return Err(CommandError::WrongArity("HMSET"));
    }
    let mut i = 2;
    while i + 1 < argv.len() {
        store.hset(&argv[1], argv[i].clone(), argv[i + 1].clone(), now_ms)?;
        i += 2;
    }
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn hincrby(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("HINCRBY"));
    }
    let delta = parse_i64_arg(&argv[3])?;
    let value = store.hincrby(&argv[1], &argv[2], delta, now_ms)?;
    Ok(RespFrame::Integer(value))
}

fn hsetnx_cmd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("HSETNX"));
    }
    let set = store.hsetnx(&argv[1], argv[2].clone(), argv[3].clone(), now_ms)?;
    Ok(RespFrame::Integer(if set { 1 } else { 0 }))
}

fn hstrlen(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("HSTRLEN"));
    }
    let len = store.hstrlen(&argv[1], &argv[2], now_ms)?;
    Ok(RespFrame::Integer(i64::try_from(len).unwrap_or(i64::MAX)))
}

// ── HEXPIRE family (Redis 7.4) ──────────────────────────────────────
//
// Part 2 of br-frankenredis-rv89. Implements the 9 hash field TTL
// commands on top of the fr-store primitives landed in
// br-frankenredis-wwz3.

/// Whether an HEXPIRE-style argument is seconds or milliseconds.
#[derive(Clone, Copy, Debug)]
enum HExpireForm {
    Seconds,
    Milliseconds,
}

fn hexpire_command_name(form: HExpireForm, absolute: bool) -> &'static str {
    match (form, absolute) {
        (HExpireForm::Seconds, false) => "HEXPIRE",
        (HExpireForm::Milliseconds, false) => "HPEXPIRE",
        (HExpireForm::Seconds, true) => "HEXPIREAT",
        (HExpireForm::Milliseconds, true) => "HPEXPIREAT",
    }
}

fn httl_command_name(unit: HashFieldTtlUnit, absolute: bool) -> &'static str {
    match (unit, absolute) {
        (HashFieldTtlUnit::Seconds, false) => "HTTL",
        (HashFieldTtlUnit::Milliseconds, false) => "HPTTL",
        (HashFieldTtlUnit::Seconds, true) => "HEXPIRETIME",
        (HashFieldTtlUnit::Milliseconds, true) => "HPEXPIRETIME",
    }
}

/// Parse `[NX|XX|GT|LT]` optional flag + mandatory `FIELDS numfields` prefix.
/// Returns `(condition, field_start_index, numfields)`.
fn parse_hash_field_ttl_flags_and_fields_header(
    argv: &[Vec<u8>],
    after_value_idx: usize,
    command_name: &'static str,
) -> Result<(HashFieldTtlCondition, usize, usize), CommandError> {
    let mut cond = HashFieldTtlCondition::None;
    let mut idx = after_value_idx;
    if idx < argv.len() {
        let tok = std::str::from_utf8(&argv[idx])
            .map_err(|_| CommandError::InvalidUtf8Argument)?;
        let matched = if tok.eq_ignore_ascii_case("NX") {
            cond = HashFieldTtlCondition::Nx;
            true
        } else if tok.eq_ignore_ascii_case("XX") {
            cond = HashFieldTtlCondition::Xx;
            true
        } else if tok.eq_ignore_ascii_case("GT") {
            cond = HashFieldTtlCondition::Gt;
            true
        } else if tok.eq_ignore_ascii_case("LT") {
            cond = HashFieldTtlCondition::Lt;
            true
        } else {
            false
        };
        if matched {
            idx += 1;
        }
    }
    // FIELDS <numfields> field [field ...]
    if idx >= argv.len() {
        return Err(CommandError::WrongArity(command_name));
    }
    let token = std::str::from_utf8(&argv[idx])
        .map_err(|_| CommandError::InvalidUtf8Argument)?;
    if !token.eq_ignore_ascii_case("FIELDS") {
        return Err(CommandError::SyntaxError);
    }
    idx += 1;
    if idx >= argv.len() {
        return Err(CommandError::WrongArity(command_name));
    }
    let numfields = parse_i64_arg(&argv[idx])?;
    if numfields < 1 {
        return Err(CommandError::Custom(
            "ERR Parameter `numFields` should be greater than 0".to_string(),
        ));
    }
    let numfields = usize::try_from(numfields).map_err(|_| CommandError::InvalidInteger)?;
    idx += 1;
    let remaining = argv.len().saturating_sub(idx);
    if remaining != numfields {
        return Err(CommandError::Custom(
            "ERR Parameter `numFields` is more than number of arguments".to_string(),
        ));
    }
    Ok((cond, idx, numfields))
}

fn hexpire_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
    form: HExpireForm,
    absolute: bool,
) -> Result<RespFrame, CommandError> {
    let cmd_name = hexpire_command_name(form, absolute);
    // argv[0]=CMD, [1]=key, [2]=N, [3..]=[flag]+FIELDS+numfields+fields...
    // Minimum legal form (fields header present): 5 args + at least 1 field → 6.
    // With 5 args we still enter parsing so the numfields-zero / missing-FIELDS
    // error wins over the generic arity error, matching upstream's error
    // precedence.
    if argv.len() < 5 {
        return Err(CommandError::WrongArity(cmd_name));
    }
    let key = argv[1].as_slice();
    let raw_value = parse_i64_arg(&argv[2])?;
    // Compute absolute deadline in ms.
    let deadline_ms: u64 = match (form, absolute) {
        (HExpireForm::Seconds, false) => {
            if raw_value < 0 {
                return Err(CommandError::Custom(
                    "ERR invalid expire time in 'hexpire' command".to_string(),
                ));
            }
            now_ms.saturating_add((raw_value as u64).saturating_mul(1000))
        }
        (HExpireForm::Milliseconds, false) => {
            if raw_value < 0 {
                return Err(CommandError::Custom(
                    "ERR invalid expire time in 'hpexpire' command".to_string(),
                ));
            }
            now_ms.saturating_add(raw_value as u64)
        }
        (HExpireForm::Seconds, true) => {
            if raw_value < 0 {
                return Err(CommandError::Custom(
                    "ERR invalid expire time in 'hexpireat' command".to_string(),
                ));
            }
            (raw_value as u64).saturating_mul(1000)
        }
        (HExpireForm::Milliseconds, true) => {
            if raw_value < 0 {
                return Err(CommandError::Custom(
                    "ERR invalid expire time in 'hpexpireat' command".to_string(),
                ));
            }
            raw_value as u64
        }
    };

    let (cond, fields_start, numfields) =
        parse_hash_field_ttl_flags_and_fields_header(argv, 3, cmd_name)?;

    // Upstream emits "hexpire"/"hpexpire"/"hexpireat"/"hpexpireat" events on
    // every successful (including already-expired) per-field TTL set.
    // (br-frankenredis-7jhg)
    let event = match (form, absolute) {
        (HExpireForm::Seconds, false) => "hexpire",
        (HExpireForm::Milliseconds, false) => "hpexpire",
        (HExpireForm::Seconds, true) => "hexpireat",
        (HExpireForm::Milliseconds, true) => "hpexpireat",
    };
    let mut replies = Vec::with_capacity(numfields);
    for f_idx in 0..numfields {
        let field = argv[fields_start + f_idx].as_slice();
        let outcome =
            store.hash_field_set_abs_expiry_with_event(key, field, deadline_ms, cond, now_ms, event);
        let code = match outcome {
            HashFieldTtlSet::Applied => 1,
            HashFieldTtlSet::AppliedAlreadyExpired => 2,
            HashFieldTtlSet::ConditionNotMet => 0,
            HashFieldTtlSet::FieldMissing => -2,
            HashFieldTtlSet::KeyMissing => -2,
            HashFieldTtlSet::WrongType => return Err(CommandError::Custom(
                "WRONGTYPE Operation against a key holding the wrong kind of value".to_string(),
            )),
        };
        replies.push(RespFrame::Integer(code));
    }
    Ok(RespFrame::Array(Some(replies)))
}

fn parse_hash_field_ttl_fields_only_header(
    argv: &[Vec<u8>],
    command_name: &'static str,
) -> Result<(usize, usize), CommandError> {
    // argv[0]=CMD, [1]=key, [2]="FIELDS", [3]=numfields, [4..]=fields
    if argv.len() < 5 {
        return Err(CommandError::WrongArity(command_name));
    }
    let token = std::str::from_utf8(&argv[2])
        .map_err(|_| CommandError::InvalidUtf8Argument)?;
    if !token.eq_ignore_ascii_case("FIELDS") {
        return Err(CommandError::SyntaxError);
    }
    let numfields = parse_i64_arg(&argv[3])?;
    if numfields < 1 {
        return Err(CommandError::Custom(
            "ERR Parameter `numFields` should be greater than 0".to_string(),
        ));
    }
    let numfields = usize::try_from(numfields).map_err(|_| CommandError::InvalidInteger)?;
    let fields_start = 4;
    let remaining = argv.len().saturating_sub(fields_start);
    if remaining != numfields {
        return Err(CommandError::Custom(
            "ERR Parameter `numFields` is more than number of arguments".to_string(),
        ));
    }
    Ok((fields_start, numfields))
}

fn httl_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
    unit: HashFieldTtlUnit,
    absolute: bool,
) -> Result<RespFrame, CommandError> {
    let cmd_name = httl_command_name(unit, absolute);
    let (fields_start, numfields) = parse_hash_field_ttl_fields_only_header(argv, cmd_name)?;
    let key = argv[1].as_slice();

    let mut replies = Vec::with_capacity(numfields);
    for f_idx in 0..numfields {
        let field = argv[fields_start + f_idx].as_slice();
        let ttl = store.hash_field_ttl(key, field, now_ms, unit, absolute);
        let code: i64 = match ttl {
            HashFieldTtl::Remaining(v) => i64::try_from(v).unwrap_or(i64::MAX),
            HashFieldTtl::NoTtl => -1,
            HashFieldTtl::FieldMissing => -2,
            HashFieldTtl::KeyMissing => -2,
            HashFieldTtl::WrongType => return Err(CommandError::Custom(
                "WRONGTYPE Operation against a key holding the wrong kind of value".to_string(),
            )),
            // Expired field is surfaced the same as FieldMissing at the wire
            // (upstream reaps the field before reporting); part 3 wires the
            // actual lazy-delete so this branch becomes observable.
            HashFieldTtl::Expired => -2,
        };
        replies.push(RespFrame::Integer(code));
    }
    Ok(RespFrame::Array(Some(replies)))
}

/// HGETEX key [EX sec | PX ms | EXAT unix-s | PXAT unix-ms | PERSIST] FIELDS n ...
///
/// Returns an array of bulk strings: the value of each requested field (or
/// nil for missing / just-reaped fields). When a TTL-modifying flag is
/// present, also updates the per-field TTL for each requested field using
/// the upstream-matching semantics (set to the provided deadline, or drop
/// with PERSIST).
fn hgetex_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    // Minimum: HGETEX key FIELDS n f1 → 5 args. No TTL flag is allowed too.
    if argv.len() < 5 {
        return Err(CommandError::WrongArity("HGETEX"));
    }
    let key = argv[1].as_slice();

    // Optional TTL modifier at argv[2..]. One of:
    //   EX sec   PX ms   EXAT unix-s   PXAT unix-ms   PERSIST
    #[derive(Clone, Copy)]
    enum TtlAction {
        None,
        SetAbsMs(u64),
        Persist,
    }
    let (ttl_action, fields_token_idx) = {
        if argv.len() >= 5 {
            let tok = std::str::from_utf8(&argv[2])
                .map_err(|_| CommandError::InvalidUtf8Argument)?;
            if tok.eq_ignore_ascii_case("FIELDS") {
                (TtlAction::None, 2)
            } else if tok.eq_ignore_ascii_case("PERSIST") {
                (TtlAction::Persist, 3)
            } else if tok.eq_ignore_ascii_case("EX")
                || tok.eq_ignore_ascii_case("PX")
                || tok.eq_ignore_ascii_case("EXAT")
                || tok.eq_ignore_ascii_case("PXAT")
            {
                if argv.len() < 7 {
                    return Err(CommandError::WrongArity("HGETEX"));
                }
                let raw = parse_i64_arg(&argv[3])?;
                if raw < 0 {
                    return Err(CommandError::Custom(
                        "ERR invalid expire time in 'hgetex' command".to_string(),
                    ));
                }
                let deadline = if tok.eq_ignore_ascii_case("EX") {
                    now_ms.saturating_add((raw as u64).saturating_mul(1000))
                } else if tok.eq_ignore_ascii_case("PX") {
                    now_ms.saturating_add(raw as u64)
                } else if tok.eq_ignore_ascii_case("EXAT") {
                    (raw as u64).saturating_mul(1000)
                } else {
                    raw as u64
                };
                (TtlAction::SetAbsMs(deadline), 4)
            } else {
                return Err(CommandError::SyntaxError);
            }
        } else {
            return Err(CommandError::WrongArity("HGETEX"));
        }
    };

    // Parse the mandatory FIELDS numfields header.
    if fields_token_idx >= argv.len() {
        return Err(CommandError::WrongArity("HGETEX"));
    }
    let tok = std::str::from_utf8(&argv[fields_token_idx])
        .map_err(|_| CommandError::InvalidUtf8Argument)?;
    if !tok.eq_ignore_ascii_case("FIELDS") {
        return Err(CommandError::SyntaxError);
    }
    let num_idx = fields_token_idx + 1;
    if num_idx >= argv.len() {
        return Err(CommandError::WrongArity("HGETEX"));
    }
    let numfields = parse_i64_arg(&argv[num_idx])?;
    if numfields < 1 {
        return Err(CommandError::Custom(
            "ERR Parameter `numFields` should be greater than 0".to_string(),
        ));
    }
    let numfields = usize::try_from(numfields).map_err(|_| CommandError::InvalidInteger)?;
    let fields_start = num_idx + 1;
    let remaining = argv.len().saturating_sub(fields_start);
    if remaining != numfields {
        return Err(CommandError::Custom(
            "ERR Parameter `numFields` is more than number of arguments".to_string(),
        ));
    }

    // Read each field's value first (before mutating TTL) so the returned
    // vector reflects the pre-modification state per upstream semantics.
    let mut replies = Vec::with_capacity(numfields);
    for f_idx in 0..numfields {
        let field = argv[fields_start + f_idx].as_slice();
        match store.hget(key, field, now_ms) {
            Ok(Some(v)) => replies.push(RespFrame::BulkString(Some(v))),
            Ok(None) => replies.push(RespFrame::BulkString(None)),
            Err(StoreError::WrongType) => {
                return Err(CommandError::Custom(
                    "WRONGTYPE Operation against a key holding the wrong kind of value".to_string(),
                ));
            }
            Err(err) => return Err(err.into()),
        }
    }

    // Apply the TTL action for every field that still exists (hget above
    // may have reaped expired fields; only live ones get the new TTL).
    match ttl_action {
        TtlAction::None => {}
        TtlAction::SetAbsMs(deadline) => {
            for f_idx in 0..numfields {
                let field = argv[fields_start + f_idx].as_slice();
                let _ = store.hash_field_set_abs_expiry_with_event(
                    key,
                    field,
                    deadline,
                    HashFieldTtlCondition::None,
                    now_ms,
                    "hexpire",
                );
            }
        }
        TtlAction::Persist => {
            for f_idx in 0..numfields {
                let field = argv[fields_start + f_idx].as_slice();
                let _ = store.hash_field_persist_with_event(key, field);
            }
        }
    }

    Ok(RespFrame::Array(Some(replies)))
}

/// HGETDEL key FIELDS n field ...
///
/// Returns an array of bulk strings with the value of each field (or nil
/// for missing fields), then deletes each specified field from the hash.
/// Equivalent to atomic HMGET + HDEL over the same field set.
fn hgetdel_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    let (fields_start, numfields) =
        parse_hash_field_ttl_fields_only_header(argv, "HGETDEL")?;
    let key = argv[1].as_slice();

    let mut replies = Vec::with_capacity(numfields);
    let mut owned_fields: Vec<Vec<u8>> = Vec::with_capacity(numfields);
    for f_idx in 0..numfields {
        let field = argv[fields_start + f_idx].as_slice();
        match store.hget(key, field, now_ms) {
            Ok(Some(v)) => replies.push(RespFrame::BulkString(Some(v))),
            Ok(None) => replies.push(RespFrame::BulkString(None)),
            Err(StoreError::WrongType) => {
                return Err(CommandError::Custom(
                    "WRONGTYPE Operation against a key holding the wrong kind of value".to_string(),
                ));
            }
            Err(err) => return Err(err.into()),
        }
        owned_fields.push(field.to_vec());
    }
    let refs: Vec<&[u8]> = owned_fields.iter().map(Vec::as_slice).collect();
    match store.hdel(key, &refs, now_ms) {
        Ok(_) | Err(StoreError::WrongType) => {}
        Err(err) => return Err(err.into()),
    }
    Ok(RespFrame::Array(Some(replies)))
}

fn hpersist_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    _now_ms: u64,
) -> Result<RespFrame, CommandError> {
    let (fields_start, numfields) =
        parse_hash_field_ttl_fields_only_header(argv, "HPERSIST")?;
    let key = argv[1].as_slice();

    let mut replies = Vec::with_capacity(numfields);
    for f_idx in 0..numfields {
        let field = argv[fields_start + f_idx].as_slice();
        // hash_field_persist_with_event emits "hpersist" NOTIFY_HASH on
        // the Persisted branch. (br-frankenredis-7jhg)
        let outcome = store.hash_field_persist_with_event(key, field);
        let code: i64 = match outcome {
            HashFieldPersistResult::Persisted => 1,
            HashFieldPersistResult::NoTtl => -1,
            HashFieldPersistResult::FieldMissing => -2,
            HashFieldPersistResult::KeyMissing => -2,
            HashFieldPersistResult::WrongType => return Err(CommandError::Custom(
                "WRONGTYPE Operation against a key holding the wrong kind of value".to_string(),
            )),
        };
        replies.push(RespFrame::Integer(code));
    }
    Ok(RespFrame::Array(Some(replies)))
}

fn lpush(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("LPUSH"));
    }
    let len = store.lpush(&argv[1], &argv[2..], now_ms)?;
    Ok(RespFrame::Integer(i64::try_from(len).unwrap_or(i64::MAX)))
}

