fn cluster_shards_reply(store: &Store) -> RespFrame {
    let node = RespFrame::Array(Some(vec![
        hello_bulk("id"),
        RespFrame::BulkString(Some(store.server_run_id.as_bytes().to_vec())),
        hello_bulk("port"),
        RespFrame::Integer(i64::from(store.server_port)),
        hello_bulk("ip"),
        hello_bulk("127.0.0.1"),
        hello_bulk("endpoint"),
        hello_bulk("127.0.0.1"),
        hello_bulk("role"),
        hello_bulk("master"),
        hello_bulk("replication-offset"),
        RespFrame::Integer(0),
        hello_bulk("health"),
        hello_bulk("online"),
    ]));
    let shard = RespFrame::Array(Some(vec![
        hello_bulk("slots"),
        RespFrame::Array(Some(vec![RespFrame::Integer(0), RespFrame::Integer(16383)])),
        hello_bulk("nodes"),
        RespFrame::Array(Some(vec![node])),
    ]));
    RespFrame::Array(Some(vec![shard]))
}

// ── CLUSTER ─────────────────────────────────────────────────────────

fn cluster_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("CLUSTER"));
    }
    let sub = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if sub.eq_ignore_ascii_case("HELP")
        || sub.eq_ignore_ascii_case("INFO")
        || sub.eq_ignore_ascii_case("SLOTS")
        || sub.eq_ignore_ascii_case("NODES")
        || sub.eq_ignore_ascii_case("LINKS")
    {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        return Err(cluster_disabled_error());
    }
    if sub.eq_ignore_ascii_case("MYID") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        return Ok(RespFrame::BulkString(Some(
            store.server_run_id.as_bytes().to_vec(),
        )));
    }
    if sub.eq_ignore_ascii_case("SHARDS") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        return Ok(cluster_shards_reply(store));
    }
    if sub.eq_ignore_ascii_case("MYSHARDID") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        return Ok(RespFrame::BulkString(Some(
            store.cluster_shard_id.as_bytes().to_vec(),
        )));
    }
    if sub.eq_ignore_ascii_case("KEYSLOT") {
        if argv.len() != 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let slot = fr_store::crc16_slot(&argv[2]);
        return Ok(RespFrame::Integer(i64::from(slot)));
    }
    if sub.eq_ignore_ascii_case("GETKEYSINSLOT") {
        if argv.len() != 4 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let slot = parse_i64_arg(&argv[2])?;
        if !(0..=16383).contains(&slot) {
            return Err(CommandError::Custom("ERR Invalid slot".to_string()));
        }
        let count = parse_i64_arg(&argv[3])?;
        if count < 0 {
            return Err(CommandError::InvalidInteger);
        }
        let keys = store.keys_in_slot(slot as u16, count as usize, now_ms);
        let frames: Vec<RespFrame> = keys
            .into_iter()
            .map(|k| RespFrame::BulkString(Some(k)))
            .collect();
        return Ok(RespFrame::Array(Some(frames)));
    }
    if sub.eq_ignore_ascii_case("COUNTKEYSINSLOT") {
        if argv.len() != 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let slot = parse_i64_arg(&argv[2])?;
        if !(0..=16383).contains(&slot) {
            return Err(CommandError::Custom("ERR Invalid slot".to_string()));
        }
        let count = store.count_keys_in_slot(slot as u16, now_ms);
        return Ok(RespFrame::Integer(count as i64));
    }
    if sub.eq_ignore_ascii_case("RESET") {
        if argv.len() > 3 {
            if store.script_nesting_level >= 1 {
                return Err(cluster_subcommand_syntax_error(sub));
            }
            if !store.cluster_enabled {
                return Err(cluster_disabled_error());
            }
            return Err(cluster_subcommand_syntax_error(sub));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        if let Some(mode) = argv.get(2) {
            let mode = std::str::from_utf8(mode).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if !mode.eq_ignore_ascii_case("SOFT") && !mode.eq_ignore_ascii_case("HARD") {
                return Err(CommandError::SyntaxError);
            }
        }
        let db_index = store.dispatch_client_ctx.db_index;
        if store.dbsize_in_db(db_index) != 0 {
            return Err(cluster_reset_with_keys_error());
        }
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    // ── CLUSTER admin subcommands (first-pass per br-frankenredis-jsr7) ──
    //
    // Upstream cluster.c::clusterCommand wires each of these with distinct
    // validation + reply semantics. We implement arity + syntax validation
    // against the upstream shape; for commands that need a real node map
    // (which fr-repl does not yet expose), we accept-OK for no-op admin
    // flows and surface upstream-matching specific errors ("Unknown node X",
    // "DB must be empty ...", etc.) rather than the blanket "cluster
    // support disabled" string. Commands still punted to that blanket
    // error because they need a slot map / config epoch / node registry:
    //   SET-CONFIG-EPOCH, SLOTSTATE.
    if sub.eq_ignore_ascii_case("MEET") {
        // CLUSTER MEET <host> <port> [cluster-bus-port]
        if argv.len() != 4 && argv.len() != 5 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let host = std::str::from_utf8(&argv[2])
            .map_err(|_| CommandError::InvalidUtf8Argument)?;
        let port = std::str::from_utf8(&argv[3])
            .map_err(|_| CommandError::InvalidUtf8Argument)?;
        if parse_i64_arg(&argv[3]).is_err() {
            return Err(CommandError::Custom(format!(
                "ERR Invalid node address specified: {host}:{port}"
            )));
        }
        if let Some(bus_port) = argv.get(4)
            && parse_i64_arg(bus_port).is_err()
        {
            let bus_port_str = std::str::from_utf8(bus_port)
                .map_err(|_| CommandError::InvalidUtf8Argument)?;
            return Err(CommandError::Custom(format!(
                "ERR Invalid base port specified: {bus_port_str}"
            )));
        }
        // Accept but do not yet actually start a cluster handshake — a real
        // node registry is a separate work item.
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    if sub.eq_ignore_ascii_case("FORGET") || sub.eq_ignore_ascii_case("REPLICATE") {
        // CLUSTER FORGET <node-id> / CLUSTER REPLICATE <node-id>
        if argv.len() != 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let node_id = std::str::from_utf8(&argv[2])
            .map_err(|_| CommandError::InvalidUtf8Argument)?;
        return Err(CommandError::Custom(format!(
            "ERR Unknown node {node_id}"
        )));
    }
    if sub.eq_ignore_ascii_case("REPLICAS") {
        // CLUSTER REPLICAS <node-id> — upstream returns the replica array or
        // "The specified node is not known or can't be a replica" error.
        if argv.len() != 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let _node_id = std::str::from_utf8(&argv[2])
            .map_err(|_| CommandError::InvalidUtf8Argument)?;
        return Err(CommandError::Custom(
            "ERR The specified node is not known or can't be a replica".to_string(),
        ));
    }
    if sub.eq_ignore_ascii_case("FAILOVER") {
        // CLUSTER FAILOVER [FORCE | TAKEOVER]
        if argv.len() > 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        if let Some(flag) = argv.get(2) {
            let flag_str = std::str::from_utf8(flag)
                .map_err(|_| CommandError::InvalidUtf8Argument)?;
            if !flag_str.eq_ignore_ascii_case("FORCE")
                && !flag_str.eq_ignore_ascii_case("TAKEOVER")
            {
                return Err(CommandError::SyntaxError);
            }
        }
        // Upstream: "You should send CLUSTER FAILOVER to a replica" when
        // issued on a master. We treat ourselves as master here (no replica
        // role tracking at the Store layer yet).
        return Err(CommandError::Custom(
            "ERR You should send CLUSTER FAILOVER to a replica".to_string(),
        ));
    }
    if sub.eq_ignore_ascii_case("ADDSLOTS") || sub.eq_ignore_ascii_case("DELSLOTS") {
        // CLUSTER ADDSLOTS <slot> [slot] ... / CLUSTER DELSLOTS ...
        if argv.len() < 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        for slot_arg in &argv[2..] {
            let slot = parse_i64_arg(slot_arg)?;
            if !(0..=16383).contains(&slot) {
                return Err(CommandError::Custom(
                    "ERR Invalid or out of range slot".to_string(),
                ));
            }
        }
        // Accept no-op — a real slot-ownership map is a separate concern.
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    if sub.eq_ignore_ascii_case("ADDSLOTSRANGE") || sub.eq_ignore_ascii_case("DELSLOTSRANGE") {
        // CLUSTER ADDSLOTSRANGE <start> <end> [<start> <end> ...]
        if argv.len() < 4 || !argv.len().is_multiple_of(2) {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let mut i = 2;
        while i + 1 < argv.len() {
            let start = parse_i64_arg(&argv[i])?;
            let end = parse_i64_arg(&argv[i + 1])?;
            if !(0..=16383).contains(&start) || !(0..=16383).contains(&end) {
                return Err(CommandError::Custom(
                    "ERR Invalid or out of range slot".to_string(),
                ));
            }
            if start > end {
                return Err(CommandError::Custom(format!(
                    "ERR start slot number {start} is greater than end slot number {end}"
                )));
            }
            i += 2;
        }
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    if sub.eq_ignore_ascii_case("FLUSHSLOTS") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let db_index = store.dispatch_client_ctx.db_index;
        if store.dbsize_in_db(db_index) != 0 {
            return Err(CommandError::Custom(
                "ERR DB must be empty to perform CLUSTER FLUSHSLOTS.".to_string(),
            ));
        }
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    if sub.eq_ignore_ascii_case("SAVECONFIG") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        // Upstream writes cluster.conf; we don't persist cluster state yet,
        // so this is a no-op. Returning OK matches the happy-path reply.
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    if sub.eq_ignore_ascii_case("BUMPEPOCH") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        // Upstream returns "BUMPED <epoch>" or "STILL <epoch>". We don't
        // track a real config epoch yet; return BUMPED 1 as the smallest
        // advance that still parses for clients that inspect the reply.
        return Ok(RespFrame::SimpleString("BUMPED 1".to_string()));
    }
    if sub.eq_ignore_ascii_case("SET-CONFIG-EPOCH") || sub.eq_ignore_ascii_case("SLOTSTATE") {
        // Real config-epoch / slot-state machinery not yet implemented;
        // keep the blanket disabled error so clients fail-loud rather
        // than think a no-op succeeded. (jsr7 follow-up)
        return Err(cluster_disabled_error());
    }
    Err(cluster_unknown_subcommand_error(sub))
}

// ── REPLCONF ────────────────────────────────────────────────────────

fn replconf_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    if argv.len().is_multiple_of(2) {
        return Err(CommandError::SyntaxError);
    }
    let mut idx = 1;
    while idx < argv.len() {
        let option =
            std::str::from_utf8(&argv[idx]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if option.eq_ignore_ascii_case("ACK") || option.eq_ignore_ascii_case("FACK") {
            let offset = parse_i64_arg(&argv[idx + 1])?;
            if offset < 0 {
                return Err(CommandError::InvalidInteger);
            }
            if store.script_nesting_level >= 1 {
                return Err(script_noscript_command_error());
            }
            return Ok(RespFrame::SimpleString("OK".to_string()));
        }
        if option.eq_ignore_ascii_case("GETACK") {
            if store.script_nesting_level >= 1 {
                return Err(script_noscript_command_error());
            }
            return Ok(RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"REPLCONF".to_vec())),
                RespFrame::BulkString(Some(b"ACK".to_vec())),
                RespFrame::BulkString(Some(b"0".to_vec())),
            ])));
        }
        if option.eq_ignore_ascii_case("listening-port") {
            let parsed = parse_i64_arg(&argv[idx + 1])?;
            u16::try_from(parsed).map_err(|_| CommandError::InvalidInteger)?;
        } else if option.eq_ignore_ascii_case("ip-address") || option.eq_ignore_ascii_case("capa") {
            // Accept configuration pairs silently.
        } else {
            return Err(CommandError::Custom(format!(
                "ERR Unrecognized REPLCONF option: {option}"
            )));
        }
        idx += 2;
    }
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    Ok(RespFrame::SimpleString("OK".to_string()))
}

// ── PSYNC ───────────────────────────────────────────────────────────

fn psync_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    // PSYNC replid offset
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("PSYNC"));
    }
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    // In standalone mode, FULLRESYNC with the server's own run_id so
    // subsequent PSYNC retries that echo this replid can be matched. The
    // offset stays at 0 here (a full replication backlog is not yet
    // tracked at this layer — see frankenredis-fcjh for the real
    // handshake pipeline). (br-frankenredis-fcjh, partial)
    let replid = store.server_run_id.clone();
    let offset = 0;
    Ok(RespFrame::SimpleString(format!(
        "FULLRESYNC {replid} {offset}"
    )))
}

// ── REPLICAOF / SLAVEOF ─────────────────────────────────────────────

fn replicaof_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    // REPLICAOF host port / REPLICAOF NO ONE
    if argv.len() < 3 {
        return Err(CommandError::WrongArity(replicaof_command_name(argv)));
    }
    let host = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    let port = std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if host.eq_ignore_ascii_case("NO") && port.eq_ignore_ascii_case("ONE") {
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else {
        let parsed = parse_i64_arg(&argv[2])
            .map_err(|_| CommandError::Custom("ERR Invalid master port".to_string()))?;
        u16::try_from(parsed)
            .map_err(|_| CommandError::Custom("ERR Invalid master port".to_string()))?;
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        // Accept but don't actually replicate - standalone mode
        Ok(RespFrame::SimpleString("OK".to_string()))
    }
}

// ── READONLY / READWRITE ────────────────────────────────────────────

fn readonly_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    if argv.len() != 1 {
        return Err(CommandError::WrongArity("READONLY"));
    }
    // Upstream cluster.c::readonlyCommand: returns OK when cluster_enabled,
    // errors with "This instance has cluster support disabled" otherwise.
    // The actual per-client CLIENT_READONLY bit-flag is a cluster-routing
    // concern we don't yet honor; returning OK unblocks clients that use
    // READONLY as a preamble to replica-routed reads. (br-frankenredis-jsr7)
    if !store.cluster_enabled {
        return Err(CommandError::Custom(
            "ERR This instance has cluster support disabled".to_string(),
        ));
    }
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn readwrite_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    if argv.len() != 1 {
        return Err(CommandError::WrongArity("READWRITE"));
    }
    // Upstream cluster.c::readwriteCommand: mirror of readonly — OK when
    // cluster_enabled, disabled-error otherwise.
    if !store.cluster_enabled {
        return Err(CommandError::Custom(
            "ERR This instance has cluster support disabled".to_string(),
        ));
    }
    Ok(RespFrame::SimpleString("OK".to_string()))
}

// ── ZRANGESTORE ────────────────────────────────────────────────────

fn zrangestore_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    // ZRANGESTORE dst src min max [BYSCORE | BYLEX] [REV] [LIMIT offset count]
    if argv.len() < 5 {
        return Err(CommandError::WrongArity("ZRANGESTORE"));
    }
    let dst = &argv[1];
    let src = &argv[2];

    let mut byscore = false;
    let mut bylex = false;
    let mut rev = false;
    let mut limit_offset: Option<usize> = None;
    let mut limit_count: Option<usize> = None;

    let mut i = 5;
    while i < argv.len() {
        let opt = std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if opt.eq_ignore_ascii_case("BYSCORE") {
            byscore = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case("BYLEX") {
            bylex = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case("REV") {
            rev = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case("LIMIT") {
            if i + 2 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            limit_offset = Some(
                usize::try_from(parse_u64_arg(&argv[i + 1])?)
                    .map_err(|_| CommandError::InvalidInteger)?,
            );
            limit_count = parse_limit_count_arg(&argv[i + 2])?;
            i += 3;
        } else {
            return Err(CommandError::SyntaxError);
        }
    }

    if byscore && bylex {
        return Err(CommandError::SyntaxError);
    }

    let pairs: Vec<(Vec<u8>, f64)> = if byscore {
        let min = parse_score_bound(&argv[3])?;
        let max = parse_score_bound(&argv[4])?;
        let (lo, hi) = if rev { (max, min) } else { (min, max) };
        let mut result = store.zrangebyscore_withscores(src, lo, hi, now_ms)?;
        if rev {
            result.reverse();
        }
        result
    } else if bylex {
        let min_lex = &argv[3];
        let max_lex = &argv[4];
        let (lo, hi) = if rev {
            (max_lex.as_slice(), min_lex.as_slice())
        } else {
            (min_lex.as_slice(), max_lex.as_slice())
        };
        let mut members = store.zrangebylex(src, lo, hi, now_ms)?;
        if rev {
            members.reverse();
        }
        // Look up scores for each member
        let mut result = Vec::with_capacity(members.len());
        for m in members {
            let score = store.zscore(src, &m, now_ms)?.unwrap_or(0.0);
            result.push((m, score));
        }
        result
    } else {
        // Default: by rank (index)
        let start = parse_i64_arg(&argv[3])?;
        let stop = parse_i64_arg(&argv[4])?;
        if rev {
            store.zrevrange_withscores(src, start, stop, now_ms)?
        } else {
            store.zrange_withscores(src, start, stop, now_ms)?
        }
    };

    // Apply LIMIT
    let pairs = if let Some(offset) = limit_offset {
        if let Some(count) = limit_count {
            pairs.into_iter().skip(offset).take(count).collect()
        } else {
            pairs.into_iter().skip(offset).collect()
        }
    } else {
        pairs
    };

    let count = pairs.len() as i64;
    if pairs.is_empty() {
        // Delete dst if it exists
        store.del(std::slice::from_ref(dst), now_ms);
    } else {
        store.zstore_from_pairs(dst.clone(), pairs, now_ms);
    }
    Ok(RespFrame::Integer(count))
}

// ── FUNCTION ────────────────────────────────────────────────────────

fn function_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    _now_ms: u64,
) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("FUNCTION"));
    }
    let sub = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if sub.eq_ignore_ascii_case("LOAD") {
        // FUNCTION LOAD [REPLACE] function-code
        if argv.len() < 3 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "LOAD".to_string(),
            });
        }
        let mut replace = false;
        let code_idx;
        if argv.len() >= 4 {
            let flag =
                std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if flag.eq_ignore_ascii_case("REPLACE") {
                replace = true;
                code_idx = 3;
            } else {
                code_idx = 2;
            }
        } else {
            code_idx = 2;
        }
        if code_idx >= argv.len() {
            return Err(CommandError::WrongArity("FUNCTION"));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        match store.function_load(&argv[code_idx], replace) {
            Ok(name) => Ok(RespFrame::BulkString(Some(name.into_bytes()))),
            Err(e) => Err(CommandError::Store(e)),
        }
    } else if sub.eq_ignore_ascii_case("LIST") {
        // FUNCTION LIST [LIBRARYNAME pattern] [WITHCODE]
        let mut pattern = None;
        let mut with_code = false;
        let mut i = 2;
        while i < argv.len() {
            let arg =
                std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if arg.eq_ignore_ascii_case("LIBRARYNAME") {
                i += 1;
                if i < argv.len() {
                    let pat = std::str::from_utf8(&argv[i])
                        .map_err(|_| CommandError::InvalidUtf8Argument)?;
                    pattern = Some(pat.to_string());
                }
            } else if arg.eq_ignore_ascii_case("WITHCODE") {
                with_code = true;
            }
            i += 1;
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        let libs = store.function_list(pattern.as_deref());
        let mut result = Vec::new();
        for lib in libs {
            let mut entries = vec![
                RespFrame::BulkString(Some(b"library_name".to_vec())),
                RespFrame::BulkString(Some(lib.name.as_bytes().to_vec())),
                RespFrame::BulkString(Some(b"engine".to_vec())),
                // PINNED 2026-04-22 — do NOT lowercase this.
                //
                // Verified against the vendored Redis 7.2.4 source
                // (legacy_redis_code/redis/src/function_lua.c:48 defines
                // `#define LUA_ENGINE_NAME "LUA"` and line 505 registers the
                // Lua engine as `functionsRegisterEngine(LUA_ENGINE_NAME, ...)`).
                // functions.c:551-552 then emits the engine field via
                // `addReplyBulkCBuffer(c, li->ei->name, ...)`, which is the
                // registered `"LUA"` string — i.e. upstream Redis 7.2.4 emits
                // the engine name in its stored case (`"LUA"`, uppercase).
                // The matching pin in the FUNCTION STATS engines map below
                // hardcodes `b"LUA"` for the same reason.
                //
                // Prior agents have flipped this line to
                // `lib.engine.to_ascii_lowercase().into_bytes()` at least
                // four times. The empirical record on the vendored Redis
                // 7.2.4 tree is unambiguous — `to_ascii_lowercase` introduces
                // a parity divergence. The root cause of the repeated flip
                // was that the `function_list_basic` fixture in
                // crates/fr-conformance/fixtures/core_scripting.json briefly
                // expected `"lua"`; that fixture has been corrected to
                // `"LUA"` so the fixture and the code now agree.
                // If a future Redis release changes this, update both the
                // live-oracle fixture and this comment in the same commit.
                RespFrame::BulkString(Some(lib.engine.as_bytes().to_vec())),
                RespFrame::BulkString(Some(b"functions".to_vec())),
            ];
            let funcs: Vec<RespFrame> = lib
                .functions
                .iter()
                .map(|f| {
                    let func_entries = vec![
                        RespFrame::BulkString(Some(b"name".to_vec())),
                        RespFrame::BulkString(Some(f.name.as_bytes().to_vec())),
                        RespFrame::BulkString(Some(b"description".to_vec())),
                        match &f.description {
                            Some(d) => RespFrame::BulkString(Some(d.as_bytes().to_vec())),
                            None => RespFrame::BulkString(None),
                        },
                        RespFrame::BulkString(Some(b"flags".to_vec())),
                        RespFrame::Array(Some(
                            f.flags
                                .iter()
                                .map(|fl| RespFrame::BulkString(Some(fl.as_bytes().to_vec())))
                                .collect(),
                        )),
                    ];
                    RespFrame::Array(Some(func_entries))
                })
                .collect();
            entries.push(RespFrame::Array(Some(funcs)));
            if with_code {
                entries.push(RespFrame::BulkString(Some(b"library_code".to_vec())));
                entries.push(RespFrame::BulkString(Some(lib.code.clone())));
            }
            result.push(RespFrame::Array(Some(entries)));
        }
        Ok(RespFrame::Array(Some(result)))
    } else if sub.eq_ignore_ascii_case("STATS") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "STATS".to_string(),
            });
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        let (lib_count, func_count) = store.function_stats();
        Ok(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(b"running_script".to_vec())),
            // PINNED 2026-04-22 — running_script is RESP2 nil (BulkString(None))
            // when no script is executing, NOT Integer(0). Verified against
            // stock `redis:7.4` (version 7.4.8): `FUNCTION STATS` returns
            // `(nil)` in the running_script slot on an idle server. A prior
            // session briefly changed this to `RespFrame::Integer(0)`; that
            // was incorrect and has since been reverted. Leave it as nil.
            RespFrame::BulkString(None),
            RespFrame::BulkString(Some(b"engines".to_vec())),
            RespFrame::Array(Some(vec![
                // PINNED 2026-04-22 — engine name is emitted in its stored case
                // (uppercase "LUA") in both FUNCTION STATS and FUNCTION LIST;
                // see the matching pin at the `lib.engine.as_bytes()` line in
                // the FUNCTION LIST handler above.
                RespFrame::BulkString(Some(b"LUA".to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"libraries_count".to_vec())),
                    RespFrame::Integer(lib_count as i64),
                    RespFrame::BulkString(Some(b"functions_count".to_vec())),
                    RespFrame::Integer(func_count as i64),
                ])),
            ])),
        ])))
    } else if sub.eq_ignore_ascii_case("DUMP") {
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        let data = store.function_dump();
        Ok(RespFrame::BulkString(Some(data)))
    } else if sub.eq_ignore_ascii_case("RESTORE") {
        // FUNCTION RESTORE serialized-value [FLUSH|APPEND|REPLACE]
        if argv.len() < 3 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "RESTORE".to_string(),
            });
        }
        if argv.len() > 4 {
            return Err(CommandError::Custom(
                "ERR unknown subcommand or wrong number of arguments for 'RESTORE'. Try FUNCTION HELP."
                    .to_string(),
            ));
        }
        let policy = if argv.len() >= 4 {
            std::str::from_utf8(&argv[3]).map_err(|_| CommandError::InvalidUtf8Argument)?
        } else {
            ""
        };
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        match store.function_restore(&argv[2], policy) {
            Ok(()) => Ok(RespFrame::SimpleString("OK".to_string())),
            Err(e) => Err(CommandError::Store(e)),
        }
    } else if sub.eq_ignore_ascii_case("FLUSH") {
        if argv.len() > 3 {
            return Err(CommandError::WrongArity("FUNCTION"));
        }
        if argv.len() == 3 {
            let mode =
                std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if !mode.eq_ignore_ascii_case("ASYNC") && !mode.eq_ignore_ascii_case("SYNC") {
                return Ok(RespFrame::Error(
                    "ERR FUNCTION FLUSH only supports SYNC|ASYNC option".to_string(),
                ));
            }
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        store.function_flush();
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else if sub.eq_ignore_ascii_case("KILL") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "KILL".to_string(),
            });
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        Ok(RespFrame::Error(
            "NOTBUSY No scripts in execution right now.".to_string(),
        ))
    } else if sub.eq_ignore_ascii_case("DELETE") {
        if argv.len() != 3 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "DELETE".to_string(),
            });
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        let name = std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        match store.function_delete(name) {
            Ok(()) => Ok(RespFrame::SimpleString("OK".to_string())),
            Err(e) => Err(CommandError::Store(e)),
        }
    } else if sub.eq_ignore_ascii_case("HELP") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "HELP".to_string(),
            });
        }
        Ok(RespFrame::Array(Some(vec![
            hello_simple("FUNCTION <subcommand> [<arg> [value] [opt] ...]. Subcommands are:"),
            hello_simple("LOAD [REPLACE] <FUNCTION CODE>"),
            hello_simple("    Create a new library with the given library name and code."),
            hello_simple("DELETE <LIBRARY NAME>"),
            hello_simple("    Delete the given library."),
            hello_simple("LIST [LIBRARYNAME PATTERN] [WITHCODE]"),
            hello_simple("    Return general information on all the libraries:"),
            hello_simple("    * Library name"),
            hello_simple("    * The engine used to run the Library"),
            hello_simple("    * Library description"),
            hello_simple("    * Functions list"),
            hello_simple("    * Library code (if WITHCODE is given)"),
            hello_simple(
                "    It also possible to get only function that matches a pattern using LIBRARYNAME argument.",
            ),
            hello_simple("STATS"),
            hello_simple("    Return information about the current function running:"),
            hello_simple("    * Function name"),
            hello_simple("    * Command used to run the function"),
            hello_simple("    * Duration in MS that the function is running"),
            hello_simple("    If no function is running, return nil"),
            hello_simple("    In addition, returns a list of available engines."),
            hello_simple("KILL"),
            hello_simple("    Kill the current running function."),
            hello_simple("FLUSH [ASYNC|SYNC]"),
            hello_simple("    Delete all the libraries."),
            hello_simple(
                "    When called without the optional mode argument, the behavior is determined by the",
            ),
            hello_simple("    lazyfree-lazy-user-flush configuration directive. Valid modes are:"),
            hello_simple("    * ASYNC: Asynchronously flush the libraries."),
            hello_simple("    * SYNC: Synchronously flush the libraries."),
            hello_simple("DUMP"),
            hello_simple(
                "    Return a serialized payload representing the current libraries, can be restored using FUNCTION RESTORE command",
            ),
            hello_simple("RESTORE <PAYLOAD> [FLUSH|APPEND|REPLACE]"),
            hello_simple(
                "    Restore the libraries represented by the given payload, it is possible to give a restore policy to",
            ),
            hello_simple("    control how to handle existing libraries (default APPEND):"),
            hello_simple("    * FLUSH: delete all existing libraries."),
            hello_simple(
                "    * APPEND: appends the restored libraries to the existing libraries. On collision, abort.",
            ),
            hello_simple(
                "    * REPLACE: appends the restored libraries to the existing libraries, On collision, replace the old",
            ),
            hello_simple(
                "      libraries with the new libraries (notice that even on this option there is a chance of failure",
            ),
            hello_simple("      in case of functions name collision with another library)."),
            hello_simple("HELP"),
            hello_simple("    Print this help."),
        ])))
    } else {
        Err(CommandError::UnknownSubcommand {
            command: "FUNCTION",
            subcommand: sub.to_string(),
        })
    }
}

fn fcall_cmd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // FCALL function numkeys [key ...] [arg ...]
    let cmd_name = std::str::from_utf8(&argv[0]).unwrap_or("FCALL");
    let is_ro = cmd_name.eq_ignore_ascii_case("FCALL_RO");

    if argv.len() < 3 {
        return Err(CommandError::WrongArity(if is_ro {
            "fcall_ro"
        } else {
            "fcall"
        }));
    }
    if store.script_nesting_level >= 1 {
        parse_eval_args(argv)?;
        return Err(script_noscript_command_error());
    }
    let func_name = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;

    // Validate function name contains only safe identifier characters to prevent
    // Lua code injection when constructing the wrapper script.
    if func_name.is_empty()
        || !func_name
            .bytes()
            .all(|b| b.is_ascii_alphanumeric() || b == b'_')
    {
        return Ok(RespFrame::Error("ERR Function not found".to_string()));
    }

    // Look up the function by name
    let (script, has_no_writes) = match store.function_get(func_name) {
        Some((lib, func)) => {
            let no_writes = func
                .flags
                .iter()
                .any(|f| f.eq_ignore_ascii_case("no-writes"));
            (lib.code.clone(), no_writes)
        }
        None => {
            return Ok(RespFrame::Error("ERR Function not found".to_string()));
        }
    };

    if is_ro && !has_no_writes {
        return Ok(RespFrame::Error(
            "ERR Can not execute a script with write flag using *_ro command.".to_string(),
        ));
    }

    let (_numkeys, keys, args) = parse_eval_args(argv)?;

    // Transform the library code for execution:
    // 1. Strip the #!lua name=... header line (not valid Lua)
    // 2. Convert redis.register_function('name', func) calls into
    //    named function definitions so they can be called directly
    let code_str = String::from_utf8_lossy(&script);
    let mut lua_lines = Vec::new();
    for line in code_str.lines() {
        let trimmed = line.trim();
        if trimmed.starts_with("#!") {
            continue;
        }
        if trimmed.contains("register_function") {
            // Transform: redis.register_function('name', function(k,a) ... end)
            // Into: function name(k,a) ... end
            if let Some(transformed) = transform_register_function(trimmed) {
                lua_lines.push(transformed);
            }
            continue;
        }
        lua_lines.push(line.to_string());
    }
    lua_lines.push(format!("return {func_name}(KEYS, ARGV)"));
    let wrapper_script = lua_lines.join("\n");

    let keys_vec: Vec<Vec<u8>> = keys.to_vec();
    let args_vec: Vec<Vec<u8>> = args.to_vec();
    let previous_read_only = store.script_read_only;
    store.script_read_only = is_ro || has_no_writes;
    store.script_nesting_level += 1;
    let result = match lua_eval::eval_script(
        wrapper_script.as_bytes(),
        &keys_vec,
        &args_vec,
        store,
        now_ms,
    ) {
        Ok(frame) => Ok(frame),
        Err(e) => Ok(RespFrame::Error(format!("ERR Error running function: {e}"))),
    };
    store.script_nesting_level -= 1;
    store.script_read_only = previous_read_only;
    result
}

/// Transform `redis.register_function('name', function(k,a) body end)` into
/// `function name(k,a) body end` so it can be called by name in our Lua evaluator.
fn transform_register_function(line: &str) -> Option<String> {
    // Match: redis.register_function('name', function(...)
    // or:    redis.register_function("name", function(...)
    let after = line
        .find("register_function")
        .map(|i| &line[i + "register_function".len()..])?;
    let after = after.trim_start().strip_prefix('(')?;
    let after = after.trim_start();
    // Extract function name from 'name' or "name"
    let (name, rest) = if let Some(stripped) = after.strip_prefix('\'') {
        let end = stripped.find('\'')?;
        (&stripped[..end], &stripped[end + 1..])
    } else if let Some(stripped) = after.strip_prefix('"') {
        let end = stripped.find('"')?;
        (&stripped[..end], &stripped[end + 1..])
    } else {
        return None;
    };
    // Skip comma and whitespace to find 'function'
    let rest = rest.trim_start().strip_prefix(',')?;
    let rest = rest.trim_start();
    // Rest should be: function(params) body end)
    // Strip trailing ')' from the register_function call
    let rest = rest.strip_prefix("function")?;
    let rest = rest.trim_end();
    let rest = rest.strip_suffix(')')?;
    Some(format!("function {name}{rest}"))
}

// ── SSUBSCRIBE / SUNSUBSCRIBE / SPUBLISH (shard Pub/Sub) ───────────

fn ssubscribe_cmd(argv: &[Vec<u8>], store: &mut Store) -> Result<RespFrame, CommandError> {
    // SSUBSCRIBE shardchannel [shardchannel ...]
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("SSUBSCRIBE"));
    }
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    if argv.len() == 2 {
        let count = store.ssubscribe(argv[1].clone()) as i64;
        return Ok(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(b"ssubscribe".to_vec())),
            RespFrame::BulkString(Some(argv[1].clone())),
            RespFrame::Integer(count),
        ])));
    }
    let mut replies = Vec::with_capacity(argv.len() - 1);
    for channel in &argv[1..] {
        let count = store.ssubscribe(channel.clone()) as i64;
        replies.push(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(b"ssubscribe".to_vec())),
            RespFrame::BulkString(Some(channel.clone())),
            RespFrame::Integer(count),
        ])));
    }
    Ok(RespFrame::Sequence(replies))
}

fn sunsubscribe_cmd(argv: &[Vec<u8>], store: &mut Store) -> Result<RespFrame, CommandError> {
    // SUNSUBSCRIBE [shardchannel ...]
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    if argv.len() < 2 {
        // Unsubscribe from all shard channels (sorted for deterministic order)
        let mut channels: Vec<Vec<u8>> = store.subscribed_shard_channels.iter().cloned().collect();
        channels.sort();
        if channels.is_empty() {
            return Ok(RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"sunsubscribe".to_vec())),
                RespFrame::BulkString(None),
                RespFrame::Integer(0),
            ])));
        }
        let mut replies = Vec::with_capacity(channels.len());
        for channel in channels {
            let count = store.sunsubscribe(&channel) as i64;
            replies.push(RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"sunsubscribe".to_vec())),
                RespFrame::BulkString(Some(channel)),
                RespFrame::Integer(count),
            ])));
        }
        return Ok(RespFrame::Sequence(replies));
    }
    if argv.len() == 2 {
        let count = store.sunsubscribe(&argv[1]) as i64;
        return Ok(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(b"sunsubscribe".to_vec())),
            RespFrame::BulkString(Some(argv[1].clone())),
            RespFrame::Integer(count),
        ])));
    }
    let mut replies = Vec::with_capacity(argv.len() - 1);
    for channel in &argv[1..] {
        let count = store.sunsubscribe(channel) as i64;
        replies.push(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(b"sunsubscribe".to_vec())),
            RespFrame::BulkString(Some(channel.clone())),
            RespFrame::Integer(count),
        ])));
    }
    Ok(RespFrame::Sequence(replies))
}

fn spublish_cmd(argv: &[Vec<u8>], store: &mut Store) -> Result<RespFrame, CommandError> {
    // SPUBLISH shardchannel message
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("SPUBLISH"));
    }
    if store.dispatch_client_ctx.is_pubsub {
        return Err(CommandError::Custom(
            "ERR Can't execute 'spublish': only (P|S)SUBSCRIBE / (P|S)UNSUBSCRIBE / PING / QUIT / RESET are allowed in this context".to_string(),
        ));
    }
    let receivers = store.spublish(&argv[1], &argv[2]);
    Ok(RespFrame::Integer(receivers as i64))
}

fn parse_score_bound(arg: &[u8]) -> Result<ScoreBound, CommandError> {
    let text = std::str::from_utf8(arg)
        .map_err(|_| CommandError::Store(fr_store::StoreError::ValueNotFloat))?
        .trim();
    if text.eq_ignore_ascii_case("-inf") {
        Ok(ScoreBound::Inclusive(f64::NEG_INFINITY))
    } else if text.eq_ignore_ascii_case("+inf") || text.eq_ignore_ascii_case("inf") {
        Ok(ScoreBound::Inclusive(f64::INFINITY))
    } else if let Some(rest) = text.strip_prefix('(') {
        let val = rest
            .trim()
            .parse::<f64>()
            .map_err(|_| CommandError::Store(fr_store::StoreError::ValueNotFloat))?;
        if val.is_nan() {
            return Err(CommandError::Store(fr_store::StoreError::ValueNotFloat));
        }
        Ok(ScoreBound::Exclusive(val))
    } else {
        let val = text
            .parse::<f64>()
            .map_err(|_| CommandError::Store(fr_store::StoreError::ValueNotFloat))?;
        if val.is_nan() {
            return Err(CommandError::Store(fr_store::StoreError::ValueNotFloat));
        }
        Ok(ScoreBound::Inclusive(val))
    }
}

fn setex(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // SETEX key seconds value
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("SETEX"));
    }
    let seconds = parse_expire_time_arg(&argv[2], "setex")?;
    let px = seconds.saturating_mul(1000);
    store.set(argv[1].clone(), argv[3].clone(), Some(px), now_ms);
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn psetex(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // PSETEX key milliseconds value
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("PSETEX"));
    }
    let px = parse_expire_time_arg(&argv[2], "psetex")?;
    store.set(argv[1].clone(), argv[3].clone(), Some(px), now_ms);
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn getdel(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("GETDEL"));
    }
    match store.getdel(&argv[1], now_ms)? {
        Some(v) => Ok(RespFrame::BulkString(Some(v))),
        None => Ok(RespFrame::BulkString(None)),
    }
}

fn getrange(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("GETRANGE"));
    }
    let start = parse_i64_arg(&argv[2])?;
    let end = parse_i64_arg(&argv[3])?;
    let result = store.getrange(&argv[1], start, end, now_ms)?;
    Ok(RespFrame::BulkString(Some(result)))
}

/// SUBSTR is a deprecated alias for GETRANGE but upstream preserves
/// the command name in wrong-arity error replies. Forwarding through
/// `getrange` would leak "GETRANGE" into the error wording.
/// (br-frankenredis-68ql)
fn substr(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("SUBSTR"));
    }
    let start = parse_i64_arg(&argv[2])?;
    let end = parse_i64_arg(&argv[3])?;
    let result = store.getrange(&argv[1], start, end, now_ms)?;
    Ok(RespFrame::BulkString(Some(result)))
}

fn setrange(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("SETRANGE"));
    }
    let offset = parse_i64_arg(&argv[2])?;
    if offset < 0 {
        return Err(CommandError::Custom(
            "ERR offset is out of range".to_string(),
        ));
    }
    let offset_u64 = u64::try_from(offset).map_err(|_| CommandError::InvalidInteger)?;
    let added_len = argv[3].len();
    if offset_u64.saturating_add(added_len as u64) > 536_870_912 {
        // Upstream reply: "string exceeds maximum allowed size
        // (proto-max-bulk-len)" (br-frankenredis-68ql).
        return Ok(RespFrame::Error(
            "ERR string exceeds maximum allowed size (proto-max-bulk-len)".to_string(),
        ));
    }
    let offset_usize = usize::try_from(offset_u64).map_err(|_| CommandError::InvalidInteger)?;
    let new_len = store.setrange(&argv[1], offset_usize, &argv[3], now_ms)?;
    Ok(RespFrame::Integer(
        i64::try_from(new_len).unwrap_or(i64::MAX),
    ))
}

fn incrbyfloat(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("INCRBYFLOAT"));
    }
    let delta = parse_f64_arg(&argv[2])?;
    let new_val = store.incrbyfloat(&argv[1], delta, now_ms)?;
    Ok(RespFrame::BulkString(Some(
        new_val.to_string().into_bytes(),
    )))
}

fn sinter(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("SINTER"));
    }
    let keys: Vec<&[u8]> = argv[1..].iter().map(Vec::as_slice).collect();
    let members = store.sinter(&keys, now_ms)?;
    let frames = members
        .into_iter()
        .map(|m| RespFrame::BulkString(Some(m)))
        .collect();
    Ok(RespFrame::Array(Some(frames)))
}

fn sunion(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("SUNION"));
    }
    let keys: Vec<&[u8]> = argv[1..].iter().map(Vec::as_slice).collect();
    let members = store.sunion(&keys, now_ms)?;
    let frames = members
        .into_iter()
        .map(|m| RespFrame::BulkString(Some(m)))
        .collect();
    Ok(RespFrame::Array(Some(frames)))
}

