/// Names of dynamically-managed params that `config_collect_store_entries` handles.
/// We skip these when iterating static defaults to avoid duplicate entries.
const CONFIG_DYNAMIC_PARAM_NAMES: &[&str] = &[
    "hash-max-listpack-entries",
    "hash-max-listpack-value",
    "hash-max-ziplist-entries",
    "hash-max-ziplist-value",
    "list-max-listpack-entries",
    "list-max-listpack-value",
    "list-max-listpack-size",
    "list-max-ziplist-size",
    "set-max-intset-entries",
    "set-max-listpack-entries",
    "zset-max-listpack-entries",
    "zset-max-listpack-value",
    "zset-max-ziplist-entries",
    "zset-max-ziplist-value",
    "lfu-decay-time",
    "maxmemory-policy",
];

/// Collect store-accessible CONFIG parameters matching a glob pattern.
///
/// This provides real CONFIG GET values for parameters stored on `Store` when
/// called via `dispatch_argv` (e.g., from Lua `redis.call("CONFIG", "GET", ...)`).
/// Runtime-level parameters (maxmemory, hz, slowlog, etc.) are only available
/// through the runtime's CONFIG handler.
fn config_collect_store_entries(pattern: &str, store: &Store, entries: &mut Vec<RespFrame>) {
    fn matches(pattern: &str, name: &str) -> bool {
        glob_match(pattern.as_bytes(), name.as_bytes())
    }
    fn push_pair(entries: &mut Vec<RespFrame>, name: &str, value: &str) {
        entries.push(RespFrame::BulkString(Some(name.as_bytes().to_vec())));
        entries.push(RespFrame::BulkString(Some(value.as_bytes().to_vec())));
    }

    let usize_params: &[(&str, usize)] = &[
        ("hash-max-listpack-entries", store.hash_max_listpack_entries),
        ("hash-max-listpack-value", store.hash_max_listpack_value),
        ("list-max-listpack-entries", store.list_max_listpack_entries),
        ("list-max-listpack-value", store.list_max_listpack_value),
        ("set-max-intset-entries", store.set_max_intset_entries),
        ("set-max-listpack-entries", store.set_max_listpack_entries),
        ("zset-max-listpack-entries", store.zset_max_listpack_entries),
        ("zset-max-listpack-value", store.zset_max_listpack_value),
        // Ziplist aliases (same live values)
        ("hash-max-ziplist-entries", store.hash_max_listpack_entries),
        ("hash-max-ziplist-value", store.hash_max_listpack_value),
        ("zset-max-ziplist-entries", store.zset_max_listpack_entries),
        ("zset-max-ziplist-value", store.zset_max_listpack_value),
    ];
    for &(name, value) in usize_params {
        if matches(pattern, name) {
            push_pair(entries, name, &value.to_string());
        }
    }
    if matches(pattern, "list-max-listpack-size") {
        push_pair(
            entries,
            "list-max-listpack-size",
            &store.list_max_listpack_size.to_string(),
        );
    }
    if matches(pattern, "list-max-ziplist-size") {
        push_pair(
            entries,
            "list-max-ziplist-size",
            &store.list_max_listpack_size.to_string(),
        );
    }
    if matches(pattern, "maxmemory-policy") {
        push_pair(
            entries,
            "maxmemory-policy",
            store.maxmemory_policy.as_config_str(),
        );
    }
    if matches(pattern, "lfu-decay-time") {
        push_pair(entries, "lfu-decay-time", &store.lfu_decay_time.to_string());
    }

    // Emit static defaults for params not dynamically managed.
    for &(name, default_value) in CONFIG_STATIC_DEFAULTS {
        if CONFIG_DYNAMIC_PARAM_NAMES.contains(&name) {
            continue;
        }
        if matches(pattern, name) {
            push_pair(entries, name, default_value);
        }
    }
}

/// Apply CONFIG SET for store-accessible parameters.
///
/// Unknown parameters are silently accepted (the runtime handles them).
fn config_apply_store_sets(pairs: &[Vec<u8>], store: &mut Store) -> Result<(), CommandError> {
    let mut i = 0;
    while i + 1 < pairs.len() {
        let name = std::str::from_utf8(&pairs[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        let val =
            std::str::from_utf8(&pairs[i + 1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        let lower = name.to_ascii_lowercase();

        match lower.as_str() {
            "hash-max-listpack-entries" | "hash-max-ziplist-entries" => {
                store.hash_max_listpack_entries = parse_config_usize(lower.as_str(), val)?;
            }
            "hash-max-listpack-value" | "hash-max-ziplist-value" => {
                store.hash_max_listpack_value = parse_config_usize(lower.as_str(), val)?;
            }
            "list-max-listpack-entries" => {
                store.list_max_listpack_entries = parse_config_usize(lower.as_str(), val)?;
            }
            "list-max-listpack-value" => {
                store.list_max_listpack_value = parse_config_usize(lower.as_str(), val)?;
            }
            "list-max-listpack-size" | "list-max-ziplist-size" => {
                store.list_max_listpack_size = parse_config_i64(lower.as_str(), val)?;
            }
            "set-max-intset-entries" => {
                store.set_max_intset_entries = parse_config_usize(lower.as_str(), val)?;
            }
            "set-max-listpack-entries" => {
                store.set_max_listpack_entries = parse_config_usize(lower.as_str(), val)?;
            }
            "zset-max-listpack-entries" | "zset-max-ziplist-entries" => {
                store.zset_max_listpack_entries = parse_config_usize(lower.as_str(), val)?;
            }
            "zset-max-listpack-value" | "zset-max-ziplist-value" => {
                store.zset_max_listpack_value = parse_config_usize(lower.as_str(), val)?;
            }
            "maxmemory-policy" => {
                store.maxmemory_policy =
                    MaxmemoryPolicy::from_config_str(val).ok_or_else(|| {
                        CommandError::Custom(format!(
                            "ERR Invalid argument '{val}' for CONFIG SET 'maxmemory-policy'"
                        ))
                    })?;
            }
            "lfu-decay-time" => {
                store.lfu_decay_time =
                    u64::try_from(parse_config_usize(lower.as_str(), val)?).unwrap_or(u64::MAX);
            }
            _ => {
                // Unknown params are silently accepted — the runtime layer
                // handles server-level params like maxmemory, hz, slowlog, etc.
            }
        }
        i += 2;
    }
    Ok(())
}

fn parse_config_parse_error(name: &str) -> CommandError {
    CommandError::Custom(format!(
        "ERR CONFIG SET failed (possibly related to argument '{name}') - argument couldn't be parsed into an integer"
    ))
}

fn parse_config_range_error(name: &str) -> CommandError {
    CommandError::Custom(format!(
        "ERR CONFIG SET failed (possibly related to argument '{name}') - argument must be between 0 and 9223372036854775807 inclusive"
    ))
}

fn parse_config_i64(name: &str, val: &str) -> Result<i64, CommandError> {
    parse_i64_arg(val.as_bytes()).map_err(|_| parse_config_parse_error(name))
}

fn parse_config_usize(name: &str, val: &str) -> Result<usize, CommandError> {
    let parsed = parse_i64_arg(val.as_bytes()).map_err(|_| parse_config_parse_error(name))?;
    if parsed < 0 {
        return Err(parse_config_range_error(name));
    }
    usize::try_from(parsed).map_err(|_| parse_config_range_error(name))
}

fn client_info_line(store: &Store, sub: &str) -> Vec<u8> {
    let ctx = &store.dispatch_client_ctx;
    let name = ctx
        .client_name
        .as_ref()
        .map(|name| String::from_utf8_lossy(name).to_string())
        .unwrap_or_default();
    let user = String::from_utf8_lossy(&ctx.authenticated_user);
    let lib_name = ctx.client_lib_name.as_deref().unwrap_or("");
    let lib_ver = ctx.client_lib_ver.as_deref().unwrap_or("");
    format!(
        "id={} addr={} laddr=127.0.0.1:{} fd=0 name={} age={} idle={} db={} sub={} psub={} ssub={} multi={} watch={} qbuf=0 qbuf-free=0 obl=0 oll=0 omem=0 tot-mem=0 events=r cmd=client|{} user={} lib-name={} lib-ver={} resp={} flags={}\r\n",
        ctx.client_id,
        ctx.peer_addr,
        store.server_port,
        name,
        ctx.age_seconds,
        ctx.idle_seconds,
        ctx.db_index,
        ctx.channel_subscriptions,
        ctx.pattern_subscriptions,
        ctx.shard_subscriptions,
        ctx.multi_count,
        ctx.watch_count,
        sub.to_ascii_lowercase(),
        user,
        lib_name,
        lib_ver,
        ctx.resp_protocol_version,
        ctx.flags,
    )
    .into_bytes()
}

fn client_wrong_subcommand_arity(subcommand: &str) -> CommandError {
    CommandError::Custom(format!(
        "ERR wrong number of arguments for 'client|{}' command",
        subcommand.to_ascii_lowercase()
    ))
}

const SCRIPT_NOSCRIPT_ERROR: &str = "ERR This Redis command is not allowed from script";
const READ_ONLY_SCRIPT_WRITE_ERROR: &str =
    "ERR Write commands are not allowed from read-only scripts.";
const CLIENT_TRACKING_REDIRECT_MISSING: &str =
    "ERR The client ID you want redirect to does not exist";
const CLIENT_TRACKING_PREFIX_REQUIRES_BCAST: &str =
    "ERR PREFIX option requires BCAST mode to be enabled";
const CLIENT_TRACKING_OPTIN_OPTOUT_CONFLICT: &str =
    "ERR You can't specify both OPTIN mode and OPTOUT mode";
const CLIENT_TRACKING_BCAST_OPT_CONFLICT: &str =
    "ERR OPTIN and OPTOUT are not compatible with BCAST";
const CLIENT_TRACKING_BCAST_SWITCH_REQUIRES_DISABLE: &str = "ERR You can't switch BCAST mode on/off before disabling tracking for this client, and then re-enabling it with a different mode.";
const CLIENT_TRACKING_OPT_SWITCH_REQUIRES_DISABLE: &str = "ERR You can't switch OPTIN/OPTOUT mode before disabling tracking for this client, and then re-enabling it with a different mode.";
const CLIENT_CACHING_REQUIRES_TRACKING: &str = "ERR CLIENT CACHING can be called only when the client is in tracking mode with OPTIN or OPTOUT mode enabled";
const CLIENT_CACHING_YES_REQUIRES_OPTIN: &str =
    "ERR CLIENT CACHING YES is only valid when tracking is enabled in OPTIN mode.";
const CLIENT_CACHING_NO_REQUIRES_OPTOUT: &str =
    "ERR CLIENT CACHING NO is only valid when tracking is enabled in OPTOUT mode.";
pub const CLIENT_PAUSE_TIMEOUT_INVALID: &str = "ERR timeout is not an integer or out of range";
pub const CLIENT_PAUSE_MODE_INVALID: &str = "ERR CLIENT PAUSE mode must be WRITE or ALL";
const CLIENT_UNBLOCK_REASON_INVALID: &str = "ERR CLIENT UNBLOCK reason should be TIMEOUT or ERROR";

fn script_noscript_command_error() -> CommandError {
    CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string())
}

fn read_only_script_write_command_error() -> CommandError {
    CommandError::Custom(READ_ONLY_SCRIPT_WRITE_ERROR.to_string())
}

fn format_eval_noscript_error(script: &[u8]) -> String {
    format!(
        "{SCRIPT_NOSCRIPT_ERROR} script: {}, on @user_script:1.",
        sha1_hex_public(script)
    )
}

fn format_eval_read_only_script_error(script: &[u8]) -> String {
    format!(
        "{READ_ONLY_SCRIPT_WRITE_ERROR} script: {}, on @user_script:1.",
        sha1_hex_public(script)
    )
}

fn eval_script_error_reply(script: &[u8], error: String) -> RespFrame {
    if error == SCRIPT_NOSCRIPT_ERROR {
        RespFrame::Error(format_eval_noscript_error(script))
    } else if error == READ_ONLY_SCRIPT_WRITE_ERROR {
        RespFrame::Error(format_eval_read_only_script_error(script))
    } else {
        RespFrame::Error(format!("ERR Error running script: {error}"))
    }
}

pub fn client_tracking_getredir_value(state: &ClientTrackingState) -> i64 {
    if !state.enabled {
        -1
    } else {
        i64::try_from(state.redirect.unwrap_or(0)).unwrap_or(i64::MAX)
    }
}

fn client_tracking_flags(state: &ClientTrackingState) -> Vec<RespFrame> {
    if !state.enabled {
        return vec![RespFrame::BulkString(Some(b"off".to_vec()))];
    }

    let mut flags = vec![RespFrame::BulkString(Some(b"on".to_vec()))];
    if state.bcast {
        flags.push(RespFrame::BulkString(Some(b"bcast".to_vec())));
    }
    if state.optin {
        flags.push(RespFrame::BulkString(Some(b"optin".to_vec())));
    }
    if state.optout {
        flags.push(RespFrame::BulkString(Some(b"optout".to_vec())));
    }
    if let Some(caching_yes) = state.caching {
        let flag = if caching_yes {
            b"caching-yes".to_vec()
        } else {
            b"caching-no".to_vec()
        };
        flags.push(RespFrame::BulkString(Some(flag)));
    }
    if state.noloop {
        flags.push(RespFrame::BulkString(Some(b"noloop".to_vec())));
    }
    flags
}

pub fn client_trackinginfo_frame(state: &ClientTrackingState) -> RespFrame {
    let prefixes = state
        .prefixes
        .iter()
        .map(|prefix| RespFrame::BulkString(Some(prefix.clone())))
        .collect();
    RespFrame::Array(Some(vec![
        RespFrame::BulkString(Some(b"flags".to_vec())),
        RespFrame::Array(Some(client_tracking_flags(state))),
        RespFrame::BulkString(Some(b"redirect".to_vec())),
        RespFrame::Integer(client_tracking_getredir_value(state)),
        RespFrame::BulkString(Some(b"prefixes".to_vec())),
        RespFrame::Array(Some(prefixes)),
    ]))
}

pub fn parse_client_tracking_state(argv: &[Vec<u8>]) -> Result<ClientTrackingState, CommandError> {
    if argv.len() < 3 {
        return Err(client_wrong_subcommand_arity("TRACKING"));
    }
    let mode = std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    let enabled = if mode.eq_ignore_ascii_case("ON") {
        true
    } else if mode.eq_ignore_ascii_case("OFF") {
        false
    } else {
        return Err(CommandError::SyntaxError);
    };

    let mut redirect = None;
    let mut bcast = false;
    let mut optin = false;
    let mut optout = false;
    let mut noloop = false;
    let mut prefixes = BTreeSet::new();
    let mut idx = 3usize;
    while idx < argv.len() {
        if argv[idx].eq_ignore_ascii_case(b"REDIRECT") {
            if idx + 1 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            let parsed = parse_i64_arg(&argv[idx + 1])?;
            if parsed <= 0 {
                return Err(CommandError::Custom(
                    CLIENT_TRACKING_REDIRECT_MISSING.to_string(),
                ));
            }
            redirect = Some(parsed as u64);
            idx += 2;
        } else if argv[idx].eq_ignore_ascii_case(b"PREFIX") {
            if idx + 1 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            prefixes.insert(argv[idx + 1].clone());
            idx += 2;
        } else if argv[idx].eq_ignore_ascii_case(b"BCAST") {
            bcast = true;
            idx += 1;
        } else if argv[idx].eq_ignore_ascii_case(b"OPTIN") {
            optin = true;
            idx += 1;
        } else if argv[idx].eq_ignore_ascii_case(b"OPTOUT") {
            optout = true;
            idx += 1;
        } else if argv[idx].eq_ignore_ascii_case(b"NOLOOP") {
            noloop = true;
            idx += 1;
        } else {
            return Err(CommandError::SyntaxError);
        }
    }

    if !enabled {
        return Ok(ClientTrackingState::default());
    }
    if !bcast && !prefixes.is_empty() {
        return Err(CommandError::Custom(
            CLIENT_TRACKING_PREFIX_REQUIRES_BCAST.to_string(),
        ));
    }
    if optin && optout {
        return Err(CommandError::Custom(
            CLIENT_TRACKING_OPTIN_OPTOUT_CONFLICT.to_string(),
        ));
    }
    if bcast && (optin || optout) {
        return Err(CommandError::Custom(
            CLIENT_TRACKING_BCAST_OPT_CONFLICT.to_string(),
        ));
    }

    Ok(ClientTrackingState {
        enabled,
        redirect,
        bcast,
        optin,
        optout,
        caching: None,
        noloop,
        prefixes,
    })
}

pub fn apply_client_tracking_update(
    current: &ClientTrackingState,
    requested: ClientTrackingState,
) -> Result<ClientTrackingState, CommandError> {
    if !requested.enabled {
        return Ok(ClientTrackingState::default());
    }

    let mut next = requested;
    if current.enabled {
        if current.bcast != next.bcast {
            return Err(CommandError::Custom(
                CLIENT_TRACKING_BCAST_SWITCH_REQUIRES_DISABLE.to_string(),
            ));
        }
        if (next.optin && current.optout) || (next.optout && current.optin) {
            return Err(CommandError::Custom(
                CLIENT_TRACKING_OPT_SWITCH_REQUIRES_DISABLE.to_string(),
            ));
        }
        next.caching = current.caching;
    }
    Ok(next)
}

pub fn validate_client_caching_mode(
    mode: &str,
    tracking: &ClientTrackingState,
) -> Result<(), CommandError> {
    if !mode.eq_ignore_ascii_case("YES") && !mode.eq_ignore_ascii_case("NO") {
        return Err(CommandError::SyntaxError);
    }
    // Upstream networking.c::clientSubcommand reports the
    // mode-specific reply regardless of whether tracking is disabled
    // or enabled-in-the-wrong-mode. (br-frankenredis-w579)
    if mode.eq_ignore_ascii_case("YES") {
        if !tracking.enabled || !tracking.optin {
            return Err(CommandError::Custom(
                CLIENT_CACHING_YES_REQUIRES_OPTIN.to_string(),
            ));
        }
    } else if !tracking.enabled || !tracking.optout {
        return Err(CommandError::Custom(
            CLIENT_CACHING_NO_REQUIRES_OPTOUT.to_string(),
        ));
    }
    Ok(())
}

pub fn apply_client_caching_mode(
    mode: &str,
    tracking: &mut ClientTrackingState,
) -> Result<(), CommandError> {
    validate_client_caching_mode(mode, tracking)?;
    tracking.caching = Some(mode.eq_ignore_ascii_case("YES"));
    Ok(())
}

#[derive(Clone, Copy)]
enum ClientReplyAction {
    On,
    Off,
    Skip,
}

fn parse_client_reply_action(argv: &[Vec<u8>]) -> Result<Option<ClientReplyAction>, CommandError> {
    let is_client_reply = argv.len() >= 2
        && argv[0].eq_ignore_ascii_case(b"CLIENT")
        && argv[1].eq_ignore_ascii_case(b"REPLY");
    if !is_client_reply {
        return Ok(None);
    }
    if argv.len() != 3 {
        return Err(client_wrong_subcommand_arity("REPLY"));
    }

    let mode = std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if mode.eq_ignore_ascii_case("ON") {
        return Ok(Some(ClientReplyAction::On));
    }
    if mode.eq_ignore_ascii_case("OFF") {
        return Ok(Some(ClientReplyAction::Off));
    }
    if mode.eq_ignore_ascii_case("SKIP") {
        return Ok(Some(ClientReplyAction::Skip));
    }
    Err(CommandError::SyntaxError)
}

pub fn apply_client_reply_state(
    argv: &[Vec<u8>],
    state: &mut ClientReplyState,
) -> Result<(), CommandError> {
    let prior_off = state.off;
    let prior_skip_next = state.skip_next;
    state.suppress_current_response = false;

    let Some(action) = parse_client_reply_action(argv)? else {
        state.suppress_current_response = prior_off || prior_skip_next;
        state.skip_next = false;
        return Ok(());
    };

    match action {
        ClientReplyAction::On => {
            state.off = false;
            state.skip_next = false;
        }
        ClientReplyAction::Off => {
            state.off = true;
            state.skip_next = false;
            state.suppress_current_response = true;
        }
        ClientReplyAction::Skip => {
            state.off = prior_off;
            state.skip_next = !prior_off;
            state.suppress_current_response = true;
        }
    }
    Ok(())
}

fn client_cmd(argv: &[Vec<u8>], store: &mut Store) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("CLIENT"));
    }
    let sub = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if sub.eq_ignore_ascii_case("SETNAME") {
        if argv.len() != 3 {
            return Err(client_wrong_subcommand_arity(sub));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        if argv[2].iter().any(|&b| b <= b' ') {
            return Err(CommandError::Custom(
                "ERR Client names cannot contain spaces, newlines or special characters."
                    .to_string(),
            ));
        }
        store.dispatch_client_ctx.client_name = if argv[2].is_empty() {
            None
        } else {
            Some(argv[2].clone())
        };
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else if sub.eq_ignore_ascii_case("GETNAME") {
        if argv.len() != 2 {
            return Err(client_wrong_subcommand_arity(sub));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        Ok(RespFrame::BulkString(
            store.dispatch_client_ctx.client_name.clone(),
        ))
    } else if sub.eq_ignore_ascii_case("ID") {
        if argv.len() != 2 {
            return Err(client_wrong_subcommand_arity(sub));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        Ok(RespFrame::Integer(
            i64::try_from(store.dispatch_client_ctx.client_id).unwrap_or(i64::MAX),
        ))
    } else if sub.eq_ignore_ascii_case("LIST") || sub.eq_ignore_ascii_case("INFO") {
        if sub.eq_ignore_ascii_case("INFO") && argv.len() != 2 {
            return Err(client_wrong_subcommand_arity(sub));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        let info_line = client_info_line(store, sub);
        if sub.eq_ignore_ascii_case("LIST") {
            let payload = if argv.len() == 2 {
                info_line
            } else if argv.len() == 4 && argv[2].eq_ignore_ascii_case(b"TYPE") {
                let kind =
                    std::str::from_utf8(&argv[3]).map_err(|_| CommandError::InvalidUtf8Argument)?;
                if (kind.eq_ignore_ascii_case("NORMAL") && !store.dispatch_client_ctx.is_pubsub)
                    || (kind.eq_ignore_ascii_case("PUBSUB") && store.dispatch_client_ctx.is_pubsub)
                {
                    info_line
                } else if kind.eq_ignore_ascii_case("MASTER")
                    || kind.eq_ignore_ascii_case("REPLICA")
                    || kind.eq_ignore_ascii_case("NORMAL")
                    || kind.eq_ignore_ascii_case("PUBSUB")
                {
                    Vec::new()
                } else {
                    return Err(CommandError::Custom(format!(
                        "ERR Unknown client type '{kind}'"
                    )));
                }
            } else if argv.len() >= 4 && argv[2].eq_ignore_ascii_case(b"ID") {
                let mut payload = Vec::new();
                for id_arg in &argv[3..] {
                    let parsed_id = parse_i64_arg(id_arg)?;
                    if parsed_id <= 0 {
                        return Err(CommandError::Custom("ERR Invalid client ID".to_string()));
                    }
                    if parsed_id as u64 == store.dispatch_client_ctx.client_id {
                        payload.extend_from_slice(&info_line);
                    }
                }
                payload
            } else {
                return Err(CommandError::SyntaxError);
            };
            return Ok(RespFrame::BulkString(Some(payload)));
        }
        Ok(RespFrame::BulkString(Some(info_line)))
    } else if sub.eq_ignore_ascii_case("NO-EVICT") || sub.eq_ignore_ascii_case("NO-TOUCH") {
        if argv.len() != 3 {
            return Err(client_wrong_subcommand_arity(sub));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        let mode = std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if !mode.eq_ignore_ascii_case("ON") && !mode.eq_ignore_ascii_case("OFF") {
            // Upstream networking.c::clientSubcommand emits the
            // generic syntax-error reply (no "argument must be
            // on/off" hint). (br-frankenredis-w579)
            return Err(CommandError::SyntaxError);
        }
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else if sub.eq_ignore_ascii_case("SETINFO") {
        if argv.len() != 4 {
            return Err(client_wrong_subcommand_arity(sub));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        let attr = std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        let val = std::str::from_utf8(&argv[3]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if attr.eq_ignore_ascii_case("LIB-NAME") {
            if val.bytes().any(|b| b <= b' ') {
                // Upstream: "LIB-NAME cannot contain spaces,
                // newlines or special characters." (br-frankenredis-w579)
                return Err(CommandError::Custom(
                    "ERR LIB-NAME cannot contain spaces, newlines or special characters."
                        .to_string(),
                ));
            }
            store.dispatch_client_ctx.client_lib_name = if val.is_empty() {
                None
            } else {
                Some(val.to_string())
            };
        } else if attr.eq_ignore_ascii_case("LIB-VER") {
            if val.bytes().any(|b| b <= b' ') {
                return Err(CommandError::Custom(
                    "ERR LIB-VER cannot contain spaces, newlines or special characters."
                        .to_string(),
                ));
            }
            store.dispatch_client_ctx.client_lib_ver = if val.is_empty() {
                None
            } else {
                Some(val.to_string())
            };
        } else {
            return Err(CommandError::Custom(format!(
                "ERR Unrecognized option '{attr}'"
            )));
        }
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else if sub.eq_ignore_ascii_case("REPLY") {
        if argv.len() != 3 {
            return Err(client_wrong_subcommand_arity(sub));
        }
        let mode = std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if !mode.eq_ignore_ascii_case("ON")
            && !mode.eq_ignore_ascii_case("OFF")
            && !mode.eq_ignore_ascii_case("SKIP")
        {
            return Err(CommandError::SyntaxError);
        }
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else if sub.eq_ignore_ascii_case("KILL") {
        // CLIENT KILL [ip:port | ID client-id | TYPE type | USER user | SKIPME yes|no]
        if argv.len() < 3 {
            return Err(client_wrong_subcommand_arity(sub));
        }

        let legacy_addr = if argv.len() == 3 {
            Some(std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?)
        } else {
            None
        };
        let mut skipme = legacy_addr.is_none();
        let mut filter_id: Option<u64> = None;
        let mut filter_type: Option<String> = None;
        let mut filter_user: Option<Vec<u8>> = None;
        let mut filter_addr = legacy_addr.map(str::to_owned);

        if legacy_addr.is_none() {
            let mut i = 2;
            while i < argv.len() {
                let opt =
                    std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;

                if opt.eq_ignore_ascii_case("ID") && i + 1 < argv.len() {
                    let id = match parse_i64_arg(&argv[i + 1]) {
                        Ok(id) if id > 0 => id as u64,
                        _ => return Err(CommandError::Custom("ERR Invalid client ID".to_string())),
                    };
                    filter_id = Some(id);
                    i += 2;
                } else if opt.eq_ignore_ascii_case("TYPE") && i + 1 < argv.len() {
                    let kind = std::str::from_utf8(&argv[i + 1])
                        .map_err(|_| CommandError::InvalidUtf8Argument)?
                        .to_string();
                    if !matches!(
                        kind.to_ascii_lowercase().as_str(),
                        "normal" | "master" | "replica" | "pubsub"
                    ) {
                        return Err(CommandError::Custom(format!(
                            "ERR Unknown client type '{kind}'"
                        )));
                    }
                    filter_type = Some(kind);
                    i += 2;
                } else if opt.eq_ignore_ascii_case("USER") && i + 1 < argv.len() {
                    filter_user = Some(argv[i + 1].clone());
                    i += 2;
                } else if opt.eq_ignore_ascii_case("ADDR") && i + 1 < argv.len() {
                    let addr = std::str::from_utf8(&argv[i + 1])
                        .map_err(|_| CommandError::InvalidUtf8Argument)?
                        .to_string();
                    filter_addr = Some(addr);
                    i += 2;
                } else if opt.eq_ignore_ascii_case("SKIPME") && i + 1 < argv.len() {
                    let val = std::str::from_utf8(&argv[i + 1])
                        .map_err(|_| CommandError::InvalidUtf8Argument)?;
                    if val.eq_ignore_ascii_case("yes") {
                        skipme = true;
                    } else if val.eq_ignore_ascii_case("no") {
                        skipme = false;
                    } else {
                        return Err(CommandError::Custom(
                            "ERR argument must be 'yes' or 'no'".to_string(),
                        ));
                    }
                    i += 2;
                } else {
                    return Err(CommandError::SyntaxError);
                }
            }
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }

        let matches_current_client = !skipme
            && filter_id.is_none_or(|id| store.dispatch_client_ctx.client_id == id)
            && filter_type.as_ref().is_none_or(|kind| {
                let current_kind = if store.dispatch_client_ctx.is_pubsub {
                    "pubsub"
                } else {
                    "normal"
                };
                current_kind.eq_ignore_ascii_case(kind)
            })
            && filter_user
                .as_ref()
                .is_none_or(|user| &store.dispatch_client_ctx.authenticated_user == user)
            && filter_addr
                .as_ref()
                .is_none_or(|addr| &store.dispatch_client_ctx.peer_addr == addr);

        if legacy_addr.is_some() {
            if matches_current_client {
                Ok(RespFrame::SimpleString("OK".to_string()))
            } else {
                Err(CommandError::Custom("ERR No such client".to_string()))
            }
        } else {
            Ok(RespFrame::Integer(i64::from(matches_current_client)))
        }
    } else if sub.eq_ignore_ascii_case("PAUSE") {
        // CLIENT PAUSE timeout [WRITE|ALL]
        if argv.len() < 3 || argv.len() > 4 {
            return Err(client_wrong_subcommand_arity(sub));
        }
        let timeout = parse_i64_arg(&argv[2])
            .map_err(|_| CommandError::Custom(CLIENT_PAUSE_TIMEOUT_INVALID.to_string()))?;
        // Upstream networking.c::pauseCommand rejects negative
        // timeouts with "ERR timeout is negative". (br-frankenredis-w579)
        if timeout < 0 {
            return Err(CommandError::Custom("ERR timeout is negative".to_string()));
        }
        if let Some(mode_arg) = argv.get(3) {
            let mode =
                std::str::from_utf8(mode_arg).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if !mode.eq_ignore_ascii_case("WRITE") && !mode.eq_ignore_ascii_case("ALL") {
                return Err(CommandError::Custom(CLIENT_PAUSE_MODE_INVALID.to_string()));
            }
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else if sub.eq_ignore_ascii_case("UNPAUSE") {
        if argv.len() != 2 {
            return Err(client_wrong_subcommand_arity(sub));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else if sub.eq_ignore_ascii_case("TRACKING") {
        // CLIENT TRACKING ON|OFF [REDIRECT id] [PREFIX prefix ...] [BCAST] [OPTIN] [OPTOUT] [NOLOOP]
        let requested = parse_client_tracking_state(argv)?;
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        let current = store.dispatch_client_ctx.client_tracking.clone();
        store.dispatch_client_ctx.client_tracking =
            apply_client_tracking_update(&current, requested)?;
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else if sub.eq_ignore_ascii_case("CACHING") {
        // CLIENT CACHING YES|NO
        if argv.len() != 3 {
            return Err(client_wrong_subcommand_arity(sub));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        let mode = std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        apply_client_caching_mode(mode, &mut store.dispatch_client_ctx.client_tracking)?;
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else if sub.eq_ignore_ascii_case("GETREDIR") {
        if argv.len() != 2 {
            return Err(client_wrong_subcommand_arity(sub));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        Ok(RespFrame::Integer(client_tracking_getredir_value(
            &store.dispatch_client_ctx.client_tracking,
        )))
    } else if sub.eq_ignore_ascii_case("TRACKINGINFO") {
        if argv.len() != 2 {
            return Err(client_wrong_subcommand_arity(sub));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        Ok(client_trackinginfo_frame(
            &store.dispatch_client_ctx.client_tracking,
        ))
    } else if sub.eq_ignore_ascii_case("UNBLOCK") {
        if argv.len() != 3 && argv.len() != 4 {
            return Err(client_wrong_subcommand_arity(sub));
        }
        let target_id = parse_i64_arg(&argv[2])?;
        if target_id <= 0 {
            return Err(CommandError::InvalidInteger);
        }
        if let Some(mode_arg) = argv.get(3) {
            let mode =
                std::str::from_utf8(mode_arg).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if !mode.eq_ignore_ascii_case("TIMEOUT") && !mode.eq_ignore_ascii_case("ERROR") {
                return Err(CommandError::Custom(
                    CLIENT_UNBLOCK_REASON_INVALID.to_string(),
                ));
            }
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        Ok(RespFrame::Integer(0))
    } else if sub.eq_ignore_ascii_case("HELP") {
        if argv.len() != 2 {
            return Err(client_wrong_subcommand_arity(sub));
        }
        Ok(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(
                b"CLIENT <subcommand> [<arg> [value] [opt] ...]. Subcommands are:".to_vec(),
            )),
            RespFrame::BulkString(Some(b"CACHING (YES|NO)".to_vec())),
            RespFrame::BulkString(Some(b"GETNAME".to_vec())),
            RespFrame::BulkString(Some(b"GETREDIR".to_vec())),
            RespFrame::BulkString(Some(b"ID".to_vec())),
            RespFrame::BulkString(Some(b"INFO".to_vec())),
            RespFrame::BulkString(Some(b"KILL <option> ...".to_vec())),
            RespFrame::BulkString(Some(
                b"LIST [TYPE (NORMAL|MASTER|REPLICA|PUBSUB)] [ID <client-id> ...]".to_vec(),
            )),
            RespFrame::BulkString(Some(b"NO-EVICT (ON|OFF)".to_vec())),
            RespFrame::BulkString(Some(b"NO-TOUCH (ON|OFF)".to_vec())),
            RespFrame::BulkString(Some(b"PAUSE <timeout> [WRITE|ALL]".to_vec())),
            RespFrame::BulkString(Some(b"REPLY (ON|OFF|SKIP)".to_vec())),
            RespFrame::BulkString(Some(b"SETINFO <option> <value>".to_vec())),
            RespFrame::BulkString(Some(b"SETNAME <connection-name>".to_vec())),
            RespFrame::BulkString(Some(b"TRACKING (ON|OFF) ...".to_vec())),
            RespFrame::BulkString(Some(b"TRACKINGINFO".to_vec())),
            RespFrame::BulkString(Some(b"UNBLOCK <client-id> [TIMEOUT|ERROR]".to_vec())),
            RespFrame::BulkString(Some(b"UNPAUSE".to_vec())),
            RespFrame::BulkString(Some(b"HELP".to_vec())),
        ])))
    } else {
        Err(CommandError::UnknownSubcommand {
            command: "CLIENT",
            subcommand: sub.to_string(),
        })
    }
}

fn time_cmd(argv: &[Vec<u8>], now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 1 {
        return Err(CommandError::WrongArity("TIME"));
    }
    let secs = now_ms / 1000;
    let usecs = (now_ms % 1000) * 1000;
    Ok(RespFrame::Array(Some(vec![
        RespFrame::BulkString(Some(secs.to_string().into_bytes())),
        RespFrame::BulkString(Some(usecs.to_string().into_bytes())),
    ])))
}

fn randomkey(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 1 {
        return Err(CommandError::WrongArity("RANDOMKEY"));
    }
    match store.randomkey(now_ms) {
        Some(key) => Ok(RespFrame::BulkString(Some(key))),
        None => Ok(RespFrame::BulkString(None)),
    }
}

// ── SCAN family ──────────────────────────────────────────────────────

struct ScanArgs {
    pattern: Option<Vec<u8>>,
    count: usize,
    type_filter: Option<Vec<u8>>,
    novalues: bool,
}

fn parse_scan_args(argv: &[Vec<u8>], start_idx: usize) -> Result<ScanArgs, CommandError> {
    // Error-reply wording MUST match upstream db.c::scanGenericCommand
    // (br-frankenredis-hjzc).
    let mut pattern: Option<Vec<u8>> = None;
    let mut count: usize = 10;
    let mut type_filter: Option<Vec<u8>> = None;
    let mut novalues = false;
    let mut i = start_idx;
    while i < argv.len() {
        let kw = std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if kw.eq_ignore_ascii_case("MATCH") {
            if i + 1 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            pattern = Some(argv[i + 1].clone());
            i += 2;
        } else if kw.eq_ignore_ascii_case("COUNT") {
            if i + 1 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            let c = parse_i64_arg(&argv[i + 1])?;
            if c <= 0 {
                // Upstream emits plain "ERR syntax error" for COUNT <= 0.
                return Err(CommandError::SyntaxError);
            }
            count = usize::try_from(c).map_err(|_| CommandError::InvalidInteger)?;
            i += 2;
        } else if kw.eq_ignore_ascii_case("TYPE") {
            if i + 1 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            type_filter = Some(argv[i + 1].clone());
            i += 2;
        } else if kw.eq_ignore_ascii_case("NOVALUES") {
            novalues = true;
            i += 1;
        } else {
            return Err(CommandError::SyntaxError);
        }
    }
    Ok(ScanArgs {
        pattern,
        count,
        type_filter,
        novalues,
    })
}

enum NegativeScanCursor {
    WrapUnsigned,
    StartAtZero,
}

/// Parse a SCAN-family cursor with Redis's strtoul-like rules. Non-numeric
/// input emits "ERR invalid cursor"; signed and leading-zero cursor tokens are
/// accepted. Negative keyspace SCAN cursors wrap into the unsigned range, while
/// compact collection scans ignore cursor state and start at 0.
/// (br-frankenredis-hjzc)
fn parse_scan_cursor(arg: &[u8], negative_mode: NegativeScanCursor) -> Result<u64, CommandError> {
    if arg.is_empty() || arg[0].is_ascii_whitespace() {
        return Err(CommandError::Custom("ERR invalid cursor".to_string()));
    }

    let (negative, digits) = match arg[0] {
        b'+' => (false, &arg[1..]),
        b'-' => (true, &arg[1..]),
        _ => (false, arg),
    };
    if digits.is_empty() {
        return Err(CommandError::Custom("ERR invalid cursor".to_string()));
    }

    let mut value = 0_u64;
    for &b in digits {
        if !b.is_ascii_digit() {
            return Err(CommandError::Custom("ERR invalid cursor".to_string()));
        }
        value = value
            .checked_mul(10)
            .and_then(|v| v.checked_add(u64::from(b - b'0')))
            .ok_or_else(|| CommandError::Custom("ERR invalid cursor".to_string()))?;
    }

    if negative {
        return Ok(match negative_mode {
            NegativeScanCursor::WrapUnsigned => 0_u64.wrapping_sub(value),
            NegativeScanCursor::StartAtZero => 0,
        });
    }
    Ok(value)
}

fn scan(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("SCAN"));
    }
    let cursor = parse_scan_cursor(&argv[1], NegativeScanCursor::WrapUnsigned)?;

    let args = parse_scan_args(argv, 2)?;
    let (next_cursor, keys) = store.scan(cursor, args.pattern.as_deref(), args.count, now_ms);

    // Apply TYPE filter if specified
    let keys: Vec<Vec<u8>> = if let Some(ref tf) = args.type_filter {
        let tf_str = std::str::from_utf8(tf).map_err(|_| CommandError::InvalidUtf8Argument)?;
        keys.into_iter()
            .filter(|k| {
                store
                    .key_type(k, now_ms)
                    .is_some_and(|t| t.eq_ignore_ascii_case(tf_str))
            })
            .collect()
    } else {
        keys
    };

    let key_frames: Vec<RespFrame> = keys
        .into_iter()
        .map(|k| RespFrame::BulkString(Some(k)))
        .collect();
    Ok(RespFrame::Array(Some(vec![
        RespFrame::BulkString(Some(next_cursor.to_string().into_bytes())),
        RespFrame::Array(Some(key_frames)),
    ])))
}

fn hscan(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("HSCAN"));
    }
    let key = &argv[1];
    let cursor = parse_scan_cursor(&argv[2], NegativeScanCursor::StartAtZero)?;

    let args = parse_scan_args(argv, 3)?;
    let (next_cursor, pairs) = store
        .hscan(key, cursor, args.pattern.as_deref(), args.count, now_ms)
        .map_err(CommandError::Store)?;

    let items: Vec<RespFrame> = if args.novalues {
        // NOVALUES: return only field names
        pairs
            .into_iter()
            .map(|(field, _)| RespFrame::BulkString(Some(field)))
            .collect()
    } else {
        // Default: return field-value pairs
        let mut result = Vec::with_capacity(pairs.len() * 2);
        for (field, value) in pairs {
            result.push(RespFrame::BulkString(Some(field)));
            result.push(RespFrame::BulkString(Some(value)));
        }
        result
    };
    Ok(RespFrame::Array(Some(vec![
        RespFrame::BulkString(Some(next_cursor.to_string().into_bytes())),
        RespFrame::Array(Some(items)),
    ])))
}

fn sscan(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("SSCAN"));
    }
    let key = &argv[1];
    let cursor = parse_scan_cursor(&argv[2], NegativeScanCursor::StartAtZero)?;

    let args = parse_scan_args(argv, 3)?;
    let (next_cursor, members) = store
        .sscan(key, cursor, args.pattern.as_deref(), args.count, now_ms)
        .map_err(CommandError::Store)?;

    let member_frames: Vec<RespFrame> = members
        .into_iter()
        .map(|m| RespFrame::BulkString(Some(m)))
        .collect();
    Ok(RespFrame::Array(Some(vec![
        RespFrame::BulkString(Some(next_cursor.to_string().into_bytes())),
        RespFrame::Array(Some(member_frames)),
    ])))
}

fn zscan(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("ZSCAN"));
    }
    let key = &argv[1];
    let cursor = parse_scan_cursor(&argv[2], NegativeScanCursor::StartAtZero)?;

    let args = parse_scan_args(argv, 3)?;
    let (next_cursor, pairs) = store
        .zscan(key, cursor, args.pattern.as_deref(), args.count, now_ms)
        .map_err(CommandError::Store)?;

    let items: Vec<RespFrame> = if args.novalues {
        // NOVALUES: return only member names (no scores)
        pairs
            .into_iter()
            .map(|(member, _)| RespFrame::BulkString(Some(member)))
            .collect()
    } else {
        // Default: return member-score pairs
        let mut result = Vec::with_capacity(pairs.len() * 2);
        for (member, score) in pairs {
            result.push(RespFrame::BulkString(Some(member)));
            result.push(RespFrame::BulkString(Some(score.to_string().into_bytes())));
        }
        result
    };
    Ok(RespFrame::Array(Some(vec![
        RespFrame::BulkString(Some(next_cursor.to_string().into_bytes())),
        RespFrame::Array(Some(items)),
    ])))
}

fn object_cmd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("OBJECT"));
    }
    let sub = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if sub.eq_ignore_ascii_case("ENCODING") {
        if argv.len() < 3 {
            return Err(CommandError::WrongSubcommandArity {
                command: "OBJECT",
                subcommand: sub.to_string(),
            });
        }
        let encoding = store.object_encoding(&argv[2], now_ms);
        match encoding {
            Some(enc) => Ok(RespFrame::BulkString(Some(enc.as_bytes().to_vec()))),
            None => Ok(RespFrame::BulkString(None)), // Redis returns null for nonexistent keys
        }
    } else if sub.eq_ignore_ascii_case("REFCOUNT") {
        if argv.len() < 3 {
            return Err(CommandError::WrongSubcommandArity {
                command: "OBJECT",
                subcommand: sub.to_string(),
            });
        }
        if store.exists_no_touch(&argv[2], now_ms) {
            Ok(RespFrame::Integer(1))
        } else {
            Ok(RespFrame::BulkString(None))
        }
    } else if sub.eq_ignore_ascii_case("IDLETIME") {
        if argv.len() != 3 {
            return Err(CommandError::WrongSubcommandArity {
                command: "OBJECT",
                subcommand: sub.to_string(),
            });
        }
        if !store.exists_no_touch(&argv[2], now_ms) {
            return Ok(RespFrame::BulkString(None));
        }
        if store.maxmemory_policy.tracks_lfu() {
            return Ok(RespFrame::Error(
                "ERR An LFU maxmemory policy is selected, idle time not tracked. Please note that when switching between policies at runtime LRU and LFU data will take some time to adjust.".to_string(),
            ));
        }
        match store.object_idletime(&argv[2], now_ms) {
            Some(idle_secs) => Ok(RespFrame::Integer(idle_secs as i64)),
            None => Ok(RespFrame::BulkString(None)),
        }
    } else if sub.eq_ignore_ascii_case("FREQ") {
        if argv.len() != 3 {
            return Err(CommandError::WrongSubcommandArity {
                command: "OBJECT",
                subcommand: sub.to_string(),
            });
        }
        if !store.exists_no_touch(&argv[2], now_ms) {
            return Ok(RespFrame::BulkString(None));
        }
        match store.object_freq(&argv[2], now_ms) {
            None => Ok(RespFrame::BulkString(None)),
            Some(freq) if store.maxmemory_policy.tracks_lfu() => Ok(RespFrame::Integer(freq.into())),
            Some(_) => Ok(RespFrame::Error(
                "ERR An LFU maxmemory policy is not selected, access frequency not tracked. Please note that when switching between policies at runtime LRU and LFU data will take some time to adjust.".to_string(),
            )),
        }
    } else if sub.eq_ignore_ascii_case("HELP") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "OBJECT",
                subcommand: "HELP".to_string(),
            });
        }
        Ok(RespFrame::Array(Some(vec![
            hello_simple("OBJECT <subcommand> [<arg> [value] [opt] ...]. Subcommands are:"),
            hello_simple("ENCODING <key>"),
            hello_simple(
                "    Return the kind of internal representation used in order to store the value",
            ),
            hello_simple("    associated with a <key>."),
            hello_simple("FREQ <key>"),
            hello_simple(
                "    Return the access frequency index of the <key>. The returned integer is",
            ),
            hello_simple(
                "    proportional to the logarithm of the recent access frequency of the key.",
            ),
            hello_simple("IDLETIME <key>"),
            hello_simple(
                "    Return the idle time of the <key>, that is the approximated number of",
            ),
            hello_simple("    seconds elapsed since the last access to the key."),
            hello_simple("REFCOUNT <key>"),
            hello_simple(
                "    Return the number of references of the value associated with the specified",
            ),
            hello_simple("    <key>."),
            hello_simple("HELP"),
            hello_simple("    Print this help."),
        ])))
    } else {
        Err(CommandError::UnknownSubcommand {
            command: "OBJECT",
            subcommand: sub.to_string(),
        })
    }
}

fn wait_cmd(argv: &[Vec<u8>]) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("WAIT"));
    }
    let numreplicas = match parse_i64_arg(&argv[1]) {
        Ok(value) if value >= 0 => value,
        Ok(_) => 0,
        Err(_) => return Err(CommandError::InvalidInteger),
    };
    let timeout_ms = parse_i64_arg(&argv[2]).map_err(|_| {
        CommandError::Custom("ERR timeout is not an integer or out of range".to_string())
    })?;
    if timeout_ms < 0 {
        return Err(CommandError::Custom("ERR timeout is negative".to_string()));
    }
    // WAIT numreplicas timeout - in standalone mode, return 0 replicas
    let _ = numreplicas;
    Ok(RespFrame::Integer(0))
}

fn slowlog_cmd(argv: &[Vec<u8>], store: &mut Store) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("SLOWLOG"));
    }
    let sub = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if sub.eq_ignore_ascii_case("GET") {
        if argv.len() > 3 {
            return Err(CommandError::WrongSubcommandArity {
                command: "SLOWLOG",
                subcommand: "GET".to_string(),
            });
        }
        if let Some(count_arg) = argv.get(2) {
            let count = parse_i64_arg(count_arg)?;
            if count < -1 {
                return Err(CommandError::Custom(
                    "ERR count should be greater than or equal to -1".to_string(),
                ));
            }
        }
        let count = if let Some(count_arg) = argv.get(2) {
            let count = parse_i64_arg(count_arg)?;
            if count == -1 {
                store.slowlog_len()
            } else {
                usize::try_from(count).map_err(|_| CommandError::InvalidInteger)?
            }
        } else {
            10
        };
        let entries = store
            .get_slowlog(count)
            .into_iter()
            .map(|entry| {
                let argv_frames: Vec<RespFrame> = entry
                    .argv
                    .into_iter()
                    .map(|arg| RespFrame::BulkString(Some(arg)))
                    .collect();
                RespFrame::Array(Some(vec![
                    RespFrame::Integer(entry.id as i64),
                    RespFrame::Integer(entry.timestamp_sec as i64),
                    RespFrame::Integer(entry.duration_us as i64),
                    RespFrame::Array(Some(argv_frames)),
                    RespFrame::BulkString(Some(b"".to_vec())),
                    RespFrame::BulkString(Some(b"".to_vec())),
                ]))
            })
            .collect();
        Ok(RespFrame::Array(Some(entries)))
    } else if sub.eq_ignore_ascii_case("LEN") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "SLOWLOG",
                subcommand: "LEN".to_string(),
            });
        }
        Ok(RespFrame::Integer(store.slowlog_len() as i64))
    } else if sub.eq_ignore_ascii_case("RESET") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "SLOWLOG",
                subcommand: "RESET".to_string(),
            });
        }
        store.reset_slowlog();
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else if sub.eq_ignore_ascii_case("HELP") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "SLOWLOG",
                subcommand: "HELP".to_string(),
            });
        }
        Ok(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(
                b"SLOWLOG <subcommand> [<arg> [value] ...]. Subcommands are:".to_vec(),
            )),
            RespFrame::BulkString(Some(
                b"GET [<count>] - Return the slow log entries.".to_vec(),
            )),
            RespFrame::BulkString(Some(
                b"LEN - Return the number of entries in the slow log.".to_vec(),
            )),
            RespFrame::BulkString(Some(b"RESET - Reset the slow log.".to_vec())),
            RespFrame::BulkString(Some(b"HELP - Return subcommand help summary.".to_vec())),
        ])))
    } else {
        Err(CommandError::UnknownSubcommand {
            command: "SLOWLOG",
            subcommand: sub.to_string(),
        })
    }
}

fn memory_cmd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("MEMORY"));
    }
    let sub = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if sub.eq_ignore_ascii_case("USAGE") {
        if argv.len() < 3 || argv.len() > 5 {
            return Err(CommandError::WrongSubcommandArity {
                command: "MEMORY",
                subcommand: "USAGE".to_string(),
            });
        }
        // Optional SAMPLES count (ignored, we do full scan)
        if argv.len() > 3 {
            let opt =
                std::str::from_utf8(&argv[3]).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if !opt.eq_ignore_ascii_case("SAMPLES") {
                return Err(CommandError::SyntaxError);
            }
            if argv.len() != 5 {
                return Err(CommandError::SyntaxError);
            }
            // Parse the samples count to validate it, but we ignore it
            let samples = parse_i64_arg(&argv[4])?;
            if samples <= 0 {
                return Err(CommandError::SyntaxError);
            }
        }
        match store.memory_usage_for_key(&argv[2], now_ms) {
            Some(bytes) => Ok(RespFrame::Integer(bytes as i64)),
            None => Ok(RespFrame::BulkString(None)),
        }
    } else if sub.eq_ignore_ascii_case("DOCTOR") {
        if argv.len() != 2 {
            return Err(CommandError::SyntaxError);
        }
        Ok(RespFrame::BulkString(Some(
            b"Sam, I have no memory problems".to_vec(),
        )))
    } else if sub.eq_ignore_ascii_case("MALLOC-STATS") {
        if argv.len() != 2 {
            return Err(CommandError::SyntaxError);
        }
        Ok(RespFrame::BulkString(Some(
            b"Memory allocator stats not available".to_vec(),
        )))
    } else if sub.eq_ignore_ascii_case("PURGE") {
        if argv.len() != 2 {
            return Err(CommandError::SyntaxError);
        }
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else if sub.eq_ignore_ascii_case("STATS") {
        if argv.len() != 2 {
            return Err(CommandError::SyntaxError);
        }
        let used = store.estimate_memory_usage_bytes();
        Ok(RespFrame::BulkString(Some(
            format!(
                "peak.allocated:{used}\r\ntotal.allocated:{used}\r\nstartup.allocated:0\r\nreplication.backlog:0\r\nclients.slaves:0\r\nclients.normal:0\r\naof.buffer:0\r\n"
            )
            .into_bytes(),
        )))
    } else if sub.eq_ignore_ascii_case("HELP") {
        if argv.len() != 2 {
            return Err(CommandError::SyntaxError);
        }
        Ok(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(
                b"MEMORY <subcommand> [<arg> [value] ...]. Subcommands are:".to_vec(),
            )),
            RespFrame::BulkString(Some(
                b"DOCTOR - Return memory problems reports.".to_vec(),
            )),
            RespFrame::BulkString(Some(
                b"MALLOC-STATS - Return internal statistics report from the memory allocator."
                    .to_vec(),
            )),
            RespFrame::BulkString(Some(
                b"PURGE - Ask the allocator to release memory.".to_vec(),
            )),
            RespFrame::BulkString(Some(
                b"STATS - Return information about the memory usage of the server.".to_vec(),
            )),
            RespFrame::BulkString(Some(
                b"USAGE <key> [SAMPLES <count>] - Return memory in bytes used by <key> and its value."
                    .to_vec(),
            )),
            RespFrame::BulkString(Some(b"HELP - Return subcommand help summary.".to_vec())),
        ])))
    } else {
        let sub_str =
            std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        Ok(RespFrame::Error(format!(
            "ERR Unknown subcommand or wrong number of arguments for '{}'. Try MEMORY HELP.",
            sub_str.to_ascii_lowercase()
        )))
    }
}

fn save_cmd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 1 {
        return Err(CommandError::WrongArity("SAVE"));
    }
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    store.record_save(now_ms, false);
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn bgsave_cmd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() > 2 {
        return Err(CommandError::SyntaxError);
    }
    if argv.len() == 2 {
        let option =
            std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if !option.eq_ignore_ascii_case("SCHEDULE") {
            return Err(CommandError::SyntaxError);
        }
    }
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    store.record_save(now_ms, true);
    store.record_bgsave_status(true);
    // Optional SCHEDULE argument — accepted but ignored
    Ok(RespFrame::SimpleString(
        "Background saving started".to_string(),
    ))
}

