    #[test]
    fn xreadgroup_validation_nogroup_and_wrongtype() {
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"1000-0".to_vec(),
                b"field".to_vec(),
                b"value".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd");

        let nogroup = dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g-missing".to_vec(),
                b"c1".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xreadgroup missing group");
        assert_eq!(
            nogroup,
            RespFrame::Error(
                "NOGROUP No such consumer group 'g-missing' for key name 's'".to_string()
            )
        );

        dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup create");

        let invalid_id = dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b"bad-id".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xreadgroup invalid id");
        assert_eq!(
            invalid_id,
            RespFrame::Error(
                "ERR Invalid stream ID specified as stream command argument".to_string()
            )
        );

        // Integer BLOCK values are accepted here; blocking wakeups are exercised
        // in fr-server integration coverage.
        let block_result = dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"BLOCK".to_vec(),
                b"0".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            0,
        );
        assert!(block_result.is_ok());

        let fractional_block = dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"BLOCK".to_vec(),
                b"1.5".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            0,
        );
        assert_eq!(
            fractional_block,
            Err(CommandError::Custom(
                "ERR timeout is not an integer or out of range".to_string()
            ))
        );

        let syntax_streams = dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"NOTSTREAMS".to_vec(),
                b"s".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("xreadgroup missing STREAMS");
        assert!(matches!(syntax_streams, CommandError::SyntaxError));

        let arity = dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b"s2".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("xreadgroup keys/ids mismatch");
        assert!(matches!(arity, CommandError::WrongArity("XREADGROUP")));

        store.set(b"k".to_vec(), b"v".to_vec(), None, 0);
        let wrongtype = dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"STREAMS".to_vec(),
                b"k".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("xreadgroup wrongtype");
        assert!(matches!(
            wrongtype,
            CommandError::Store(fr_store::StoreError::WrongType)
        ));
    }

    #[test]
    fn blocking_deadline_milliseconds_requires_integer_and_rejects_overflow() {
        assert_eq!(
            parse_blocking_deadline_milliseconds(b"0", 123),
            Ok(u64::MAX)
        );
        assert_eq!(parse_blocking_deadline_milliseconds(b"5", 123), Ok(128));
        assert_eq!(
            parse_blocking_deadline_milliseconds(b"1.5", 123),
            Err(CommandError::Custom(
                "ERR timeout is not an integer or out of range".to_string()
            ))
        );
        assert_eq!(
            parse_blocking_deadline_milliseconds(b"+1", 123),
            Err(CommandError::Custom(
                "ERR timeout is not an integer or out of range".to_string()
            ))
        );
        assert_eq!(
            parse_blocking_deadline_milliseconds(b"001", 123),
            Err(CommandError::Custom(
                "ERR timeout is not an integer or out of range".to_string()
            ))
        );
        assert_eq!(
            parse_blocking_deadline_milliseconds(b"1", u64::MAX),
            Err(CommandError::Custom(
                "ERR timeout is out of range".to_string()
            ))
        );
    }

    #[test]
    fn count_parsers_reject_noncanonical_tokens() {
        assert_eq!(
            crate::parse_u64_arg(b"+1"),
            Err(CommandError::InvalidInteger)
        );
        assert_eq!(
            crate::parse_u64_arg(b"001"),
            Err(CommandError::InvalidInteger)
        );
        assert_eq!(crate::parse_u64_arg(b"0"), Ok(0));
        assert_eq!(crate::parse_u64_arg(b"5"), Ok(5));

        assert_eq!(
            crate::parse_limit_count_arg(b"+1"),
            Err(CommandError::InvalidInteger)
        );
        assert_eq!(
            crate::parse_limit_count_arg(b"001"),
            Err(CommandError::InvalidInteger)
        );
        assert_eq!(crate::parse_limit_count_arg(b"-1"), Ok(None));
        assert_eq!(crate::parse_limit_count_arg(b"0"), Ok(Some(0)));
    }

    #[test]
    fn float_parsers_reject_whitespace() {
        assert!(matches!(
            crate::parse_f64_arg(b" 1"),
            Err(CommandError::Store(fr_store::StoreError::ValueNotFloat))
        ));
        assert!(matches!(
            crate::parse_f64_arg(b"1 "),
            Err(CommandError::Store(fr_store::StoreError::ValueNotFloat))
        ));
        assert!(matches!(
            crate::parse_f64_arg(b"\t1"),
            Err(CommandError::Store(fr_store::StoreError::ValueNotFloat))
        ));
        assert!(matches!(
            crate::parse_f64_arg(b"1\t"),
            Err(CommandError::Store(fr_store::StoreError::ValueNotFloat))
        ));
        assert_eq!(crate::parse_f64_arg(b"1"), Ok(1.0));
        assert_eq!(crate::parse_f64_arg(b"-1.5"), Ok(-1.5));

        assert!(matches!(
            crate::parse_geo_f64(b" 1"),
            Err(RespFrame::Error(msg)) if msg == "ERR value is not a valid float"
        ));
        assert!(matches!(
            crate::parse_geo_f64(b"1 "),
            Err(RespFrame::Error(msg)) if msg == "ERR value is not a valid float"
        ));
        assert_eq!(crate::parse_geo_f64(b"1"), Ok(1.0));
        assert_eq!(crate::parse_geo_f64(b"-1.5"), Ok(-1.5));
    }

