    #[test]
    fn xclaim_transfers_pending_entries_and_supports_justid() {
        let mut store = Store::new();
        for (id, value) in [("1000-0", "v0"), ("1000-1", "v1")] {
            dispatch_argv(
                &[
                    b"XADD".to_vec(),
                    b"s".to_vec(),
                    id.as_bytes().to_vec(),
                    b"field".to_vec(),
                    value.as_bytes().to_vec(),
                ],
                &mut store,
                0,
            )
            .expect("xadd");
        }
        dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup create");
        dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            10,
        )
        .expect("seed pending");

        let claimed = dispatch_argv(
            &[
                b"XCLAIM".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"c2".to_vec(),
                b"5".to_vec(),
                b"1000-0".to_vec(),
            ],
            &mut store,
            30,
        )
        .expect("xclaim");
        assert_eq!(
            claimed,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"1000-0".to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"field".to_vec())),
                    RespFrame::BulkString(Some(b"v0".to_vec())),
                ])),
            ]))]))
        );

        let summary = dispatch_argv(
            &[b"XPENDING".to_vec(), b"s".to_vec(), b"g1".to_vec()],
            &mut store,
            30,
        )
        .expect("xpending summary");
        assert_eq!(
            summary,
            RespFrame::Array(Some(vec![
                RespFrame::Integer(2),
                RespFrame::BulkString(Some(b"1000-0".to_vec())),
                RespFrame::BulkString(Some(b"1000-1".to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"c1".to_vec())),
                        RespFrame::Integer(1),
                    ])),
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"c2".to_vec())),
                        RespFrame::Integer(1),
                    ])),
                ])),
            ]))
        );

        let justid = dispatch_argv(
            &[
                b"XCLAIM".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"c2".to_vec(),
                b"5".to_vec(),
                b"1000-1".to_vec(),
                b"JUSTID".to_vec(),
            ],
            &mut store,
            40,
        )
        .expect("xclaim justid");
        assert_eq!(
            justid,
            RespFrame::Array(Some(vec![RespFrame::BulkString(Some(b"1000-1".to_vec()))]))
        );
    }

    #[test]
    fn xautoclaim_claims_by_cursor_and_returns_next_start() {
        let mut store = Store::new();
        for (id, value) in [("1000-0", "v0"), ("1000-1", "v1"), ("1000-2", "v2")] {
            dispatch_argv(
                &[
                    b"XADD".to_vec(),
                    b"s".to_vec(),
                    id.as_bytes().to_vec(),
                    b"field".to_vec(),
                    value.as_bytes().to_vec(),
                ],
                &mut store,
                0,
            )
            .expect("xadd");
        }
        dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup create");
        dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            10,
        )
        .expect("seed pending");

        let first = dispatch_argv(
            &[
                b"XAUTOCLAIM".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"c2".to_vec(),
                b"5".to_vec(),
                b"0-0".to_vec(),
                b"COUNT".to_vec(),
                b"2".to_vec(),
            ],
            &mut store,
            30,
        )
        .expect("xautoclaim first");
        assert_eq!(
            first,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"1000-2".to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"1000-0".to_vec())),
                        RespFrame::Array(Some(vec![
                            RespFrame::BulkString(Some(b"field".to_vec())),
                            RespFrame::BulkString(Some(b"v0".to_vec())),
                        ])),
                    ])),
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"1000-1".to_vec())),
                        RespFrame::Array(Some(vec![
                            RespFrame::BulkString(Some(b"field".to_vec())),
                            RespFrame::BulkString(Some(b"v1".to_vec())),
                        ])),
                    ])),
                ])),
                RespFrame::Array(Some(vec![])),
            ]))
        );

        let second = dispatch_argv(
            &[
                b"XAUTOCLAIM".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"c3".to_vec(),
                b"0".to_vec(),
                b"1000-2".to_vec(),
                b"COUNT".to_vec(),
                b"5".to_vec(),
                b"JUSTID".to_vec(),
            ],
            &mut store,
            31,
        )
        .expect("xautoclaim second");
        assert_eq!(
            second,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"0-0".to_vec())),
                RespFrame::Array(Some(vec![RespFrame::BulkString(Some(b"1000-2".to_vec()))])),
                RespFrame::Array(Some(vec![])),
            ]))
        );
    }

