    #[test]
    fn sintercard_limit_parity_matches_vendored_redis() {
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"SADD".to_vec(),
                b"s1".to_vec(),
                b"a".to_vec(),
                b"b".to_vec(),
                b"c".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("sadd s1");
        dispatch_argv(
            &[
                b"SADD".to_vec(),
                b"s2".to_vec(),
                b"b".to_vec(),
                b"c".to_vec(),
                b"d".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("sadd s2");

        let duplicate_limit = dispatch_argv(
            &[
                b"SINTERCARD".to_vec(),
                b"2".to_vec(),
                b"s1".to_vec(),
                b"s2".to_vec(),
                b"LIMIT".to_vec(),
                b"1".to_vec(),
                b"LIMIT".to_vec(),
                b"2".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("duplicate LIMIT should use last value");
        assert_eq!(duplicate_limit, RespFrame::Integer(2));

        let negative_limit = dispatch_argv(
            &[
                b"SINTERCARD".to_vec(),
                b"2".to_vec(),
                b"s1".to_vec(),
                b"s2".to_vec(),
                b"LIMIT".to_vec(),
                b"-1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("negative LIMIT should fail");
        assert_eq!(
            negative_limit,
            CommandError::Custom("ERR LIMIT can't be negative".to_string())
        );
    }

