    // ── XACK tests ──────────────────────────────────────────────────

    #[test]
    fn xack_basic() {
        let mut store = Store::new();
        // Create stream and consumer group
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"mystream".to_vec(),
                b"1-0".to_vec(),
                b"f".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"mystream".to_vec(),
                b"grp".to_vec(),
                b"0-0".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        // Read to create pending entry
        dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"grp".to_vec(),
                b"consumer1".to_vec(),
                b"COUNT".to_vec(),
                b"10".to_vec(),
                b"STREAMS".to_vec(),
                b"mystream".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            1,
        )
        .unwrap();
        // ACK the message
        let out = dispatch_argv(
            &[
                b"XACK".to_vec(),
                b"mystream".to_vec(),
                b"grp".to_vec(),
                b"1-0".to_vec(),
            ],
            &mut store,
            2,
        )
        .unwrap();
        assert_eq!(out, RespFrame::Integer(1));
    }

