    #[test]
    fn wrong_subcommand_arity_formats_redis_families_with_expected_wording() {
        for (command, subcommand) in [
            ("ACL", "SETUSER"),
            ("SLOWLOG", "GET"),
            ("XGROUP", "CREATE"),
            ("XINFO", "STREAM"),
        ] {
            let err = CommandError::WrongSubcommandArity {
                command,
                subcommand: subcommand.to_string(),
            };
            assert_eq!(
                err.to_resp(),
                RespFrame::Error(format!(
                    "ERR wrong number of arguments for '{}|{}' command",
                    command.to_ascii_lowercase(),
                    subcommand.to_ascii_lowercase()
                )),
                "command={command} subcommand={subcommand}"
            );
        }

        let config_err = CommandError::WrongSubcommandArity {
            command: "CONFIG",
            subcommand: "RESETSTAT".to_string(),
        };
        assert_eq!(
            config_err.to_resp(),
            RespFrame::Error(
                "ERR wrong number of arguments for 'config|resetstat' command".to_string()
            )
        );

        let object_err = CommandError::WrongSubcommandArity {
            command: "OBJECT",
            subcommand: "ENCODING".to_string(),
        };
        assert_eq!(
            object_err.to_resp(),
            RespFrame::Error(
                "ERR wrong number of arguments for 'object|encoding' command".to_string()
            )
        );

        let client_err = CommandError::WrongSubcommandArity {
            command: "CLIENT",
            subcommand: "PAUSE".to_string(),
        };
        assert_eq!(
            client_err.to_resp(),
            RespFrame::Error(
                "ERR wrong number of arguments for 'client|pause' command".to_string()
            )
        );
    }

    #[test]
    fn config_resetstat_clears_info_stats_counters() {
        let mut store = Store::new();
        store.stat_total_commands_processed = 12;
        store.stat_total_connections_received = 2;
        store.stat_unexpected_error_replies = 4;
        store.stat_total_error_replies = 9;
        store.stat_total_reads_processed = 13;
        store.stat_total_writes_processed = 7;
        store.stat_expired_keys = 3;
        store.stat_evicted_keys = 2;
        store.stat_expired_stale_perc = 50;
        store.stat_expire_cycle_cpu_milliseconds = 7;
        store.record_slowlog(&[b"GET".to_vec(), b"k".to_vec()], 20_000, 1);
        store.record_command_histogram("GET", 100);

        let out = dispatch_argv(&[b"CONFIG".to_vec(), b"RESETSTAT".to_vec()], &mut store, 0)
            .expect("config resetstat");
        assert_eq!(out, RespFrame::SimpleString("OK".to_string()));
        assert_eq!(store.stat_total_commands_processed, 0);
        assert_eq!(store.stat_total_connections_received, 0);
        assert_eq!(store.stat_unexpected_error_replies, 0);
        assert_eq!(store.stat_total_error_replies, 0);
        assert_eq!(store.stat_total_reads_processed, 0);
        assert_eq!(store.stat_total_writes_processed, 0);
        assert_eq!(store.stat_expired_keys, 0);
        assert_eq!(store.stat_evicted_keys, 0);
        assert_eq!(store.stat_expired_stale_perc, 0);
        assert_eq!(store.stat_expire_cycle_cpu_milliseconds, 0);
        assert_eq!(store.slowlog_len(), 0);
        assert!(store.all_command_histograms().is_empty());
    }

    #[test]
    fn config_subcommands_reject_scripts_after_arity_validation() {
        let mut store = Store::new();
        store.script_nesting_level = 1;

        let get_arity =
            dispatch_argv(&[b"CONFIG".to_vec(), b"GET".to_vec()], &mut store, 0).unwrap_err();
        assert_eq!(
            get_arity,
            CommandError::WrongSubcommandArity {
                command: "CONFIG",
                subcommand: "GET".to_string(),
            }
        );

        let set_arity = dispatch_argv(
            &[b"CONFIG".to_vec(), b"SET".to_vec(), b"foo".to_vec()],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            set_arity,
            CommandError::WrongSubcommandArity {
                command: "CONFIG",
                subcommand: "SET".to_string(),
            }
        );

        let resetstat_arity = dispatch_argv(
            &[b"CONFIG".to_vec(), b"RESETSTAT".to_vec(), b"extra".to_vec()],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            resetstat_arity,
            CommandError::WrongSubcommandArity {
                command: "CONFIG",
                subcommand: "RESETSTAT".to_string(),
            }
        );

        let rewrite_arity = dispatch_argv(
            &[b"CONFIG".to_vec(), b"REWRITE".to_vec(), b"extra".to_vec()],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            rewrite_arity,
            CommandError::WrongSubcommandArity {
                command: "CONFIG",
                subcommand: "REWRITE".to_string(),
            }
        );

        for argv in [
            vec![b"CONFIG".to_vec(), b"RESETSTAT".to_vec()],
            vec![b"CONFIG".to_vec(), b"REWRITE".to_vec()],
        ] {
            let err = dispatch_argv(&argv, &mut store, 0).unwrap_err();
            assert_eq!(err, CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string()));
        }
    }

    #[test]
    fn info_stats_reports_expire_and_evict_counters() {
        let mut store = Store::new();
        store.stat_expired_keys = 3;
        store.stat_evicted_keys = 2;
        store.stat_expired_stale_perc = 50;
        store.stat_expire_cycle_cpu_milliseconds = 7;
        store.stat_keyspace_hits = 11;
        store.stat_keyspace_misses = 4;
        store.stat_unexpected_error_replies = 2;
        store.stat_total_error_replies = 9;
        store.stat_total_reads_processed = 13;
        store.stat_total_writes_processed = 7;

        let out = dispatch_argv(&[b"INFO".to_vec(), b"stats".to_vec()], &mut store, 0)
            .expect("info stats");
        let RespFrame::BulkString(Some(bytes)) = out else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        let info = String::from_utf8(bytes).expect("utf8");
        assert!(info.contains("expired_keys:3\r\n"));
        assert!(info.contains("expired_stale_perc:50.00\r\n"));
        assert!(info.contains("expire_cycle_cpu_milliseconds:7\r\n"));
        assert!(info.contains("evicted_keys:2\r\n"));
        assert!(info.contains("total_keys_expired:3\r\n"));
        assert!(info.contains("total_keys_evicted:2\r\n"));
        assert!(info.contains("keyspace_hits:11\r\n"));
        assert!(info.contains("keyspace_misses:4\r\n"));
        assert!(info.contains("unexpected_error_replies:2\r\n"));
        assert!(info.contains("total_error_replies:9\r\n"));
        assert!(info.contains("total_reads_processed:13\r\n"));
        assert!(info.contains("total_writes_processed:7\r\n"));
    }

    #[test]
    fn info_stats_reports_network_byte_counters() {
        let mut store = Store::new();
        store.stat_total_net_input_bytes = 12345;
        store.stat_total_net_output_bytes = 67890;
        // Simulate ops sampling: 500 cmds in 100ms = 5000 ops/sec per sample
        store.stat_total_commands_processed = 500;
        store.record_ops_sec_sample(100);

        let out = dispatch_argv(&[b"INFO".to_vec(), b"stats".to_vec()], &mut store, 0)
            .expect("info stats");
        let RespFrame::BulkString(Some(bytes)) = out else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        let info = String::from_utf8(bytes).expect("utf8");
        assert!(info.contains("total_net_input_bytes:12345\r\n"), "{info}");
        assert!(info.contains("total_net_output_bytes:67890\r\n"), "{info}");
        // With only 1 of 16 samples filled, ops/sec = 5000/16 = 312
        assert!(info.contains("instantaneous_ops_per_sec:312\r\n"), "{info}");
    }

