    #[test]
    fn client_tracking_state_is_reflected_in_info_commands() {
        let mut store = Store::new();
        let out = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"TRACKING".to_vec(),
                b"ON".to_vec(),
                b"OPTIN".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::SimpleString("OK".to_string()));
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"CACHING".to_vec(), b"YES".to_vec()],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            dispatch_argv(&[b"CLIENT".to_vec(), b"GETREDIR".to_vec()], &mut store, 0).unwrap(),
            RespFrame::Integer(0)
        );
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"TRACKINGINFO".to_vec()],
                &mut store,
                0
            )
            .unwrap(),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"flags".to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"on".to_vec())),
                    RespFrame::BulkString(Some(b"optin".to_vec())),
                    RespFrame::BulkString(Some(b"caching-yes".to_vec())),
                ])),
                RespFrame::BulkString(Some(b"redirect".to_vec())),
                RespFrame::Integer(0),
                RespFrame::BulkString(Some(b"prefixes".to_vec())),
                RespFrame::Array(Some(Vec::new())),
            ]))
        );

        assert_eq!(
            dispatch_argv(
                &[
                    b"CLIENT".to_vec(),
                    b"TRACKING".to_vec(),
                    b"ON".to_vec(),
                    b"NOLOOP".to_vec(),
                    b"PREFIX".to_vec(),
                    b"foo".to_vec(),
                    b"BCAST".to_vec(),
                    b"PREFIX".to_vec(),
                    b"bar".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom(CLIENT_TRACKING_BCAST_SWITCH_REQUIRES_DISABLE.to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"TRACKINGINFO".to_vec()],
                &mut store,
                0
            )
            .unwrap(),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"flags".to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"on".to_vec())),
                    RespFrame::BulkString(Some(b"optin".to_vec())),
                    RespFrame::BulkString(Some(b"caching-yes".to_vec())),
                ])),
                RespFrame::BulkString(Some(b"redirect".to_vec())),
                RespFrame::Integer(0),
                RespFrame::BulkString(Some(b"prefixes".to_vec())),
                RespFrame::Array(Some(Vec::new())),
            ]))
        );
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLIENT".to_vec(),
                    b"TRACKING".to_vec(),
                    b"OFF".to_vec(),
                    b"PREFIX".to_vec(),
                    b"ignored".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLIENT".to_vec(),
                    b"TRACKING".to_vec(),
                    b"ON".to_vec(),
                    b"NOLOOP".to_vec(),
                    b"PREFIX".to_vec(),
                    b"foo".to_vec(),
                    b"BCAST".to_vec(),
                    b"PREFIX".to_vec(),
                    b"bar".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"TRACKINGINFO".to_vec()],
                &mut store,
                0
            )
            .unwrap(),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"flags".to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"on".to_vec())),
                    RespFrame::BulkString(Some(b"bcast".to_vec())),
                    RespFrame::BulkString(Some(b"noloop".to_vec())),
                ])),
                RespFrame::BulkString(Some(b"redirect".to_vec())),
                RespFrame::Integer(0),
                RespFrame::BulkString(Some(b"prefixes".to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"bar".to_vec())),
                    RespFrame::BulkString(Some(b"foo".to_vec())),
                ])),
            ]))
        );
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"TRACKING".to_vec(), b"OFF".to_vec()],
                &mut store,
                0
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            dispatch_argv(&[b"CLIENT".to_vec(), b"GETREDIR".to_vec()], &mut store, 0).unwrap(),
            RespFrame::Integer(-1)
        );
    }

