    #[test]
    fn client_tracking_rejected_from_scripts_after_validation() {
        let mut store = Store::new();
        store.script_nesting_level = 1;
        let before = store.dispatch_client_ctx.client_tracking.clone();

        let arity = dispatch_argv(&[b"CLIENT".to_vec(), b"TRACKING".to_vec()], &mut store, 0)
            .expect_err("client tracking arity");
        assert_eq!(arity, client_wrong_subcommand_arity("TRACKING"));

        let syntax = dispatch_argv(
            &[b"CLIENT".to_vec(), b"TRACKING".to_vec(), b"MAYBE".to_vec()],
            &mut store,
            0,
        )
        .expect_err("client tracking syntax");
        assert_eq!(syntax, CommandError::SyntaxError);

        let matrix = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"TRACKING".to_vec(),
                b"ON".to_vec(),
                b"PREFIX".to_vec(),
                b"foo".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("client tracking option matrix");
        assert_eq!(
            matrix,
            CommandError::Custom(CLIENT_TRACKING_PREFIX_REQUIRES_BCAST.to_string())
        );

        for argv in [
            vec![b"CLIENT".to_vec(), b"TRACKING".to_vec(), b"ON".to_vec()],
            vec![b"CLIENT".to_vec(), b"TRACKING".to_vec(), b"OFF".to_vec()],
        ] {
            let err = dispatch_argv(&argv, &mut store, 0).expect_err("client tracking noscript");
            assert_eq!(err, CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string()));
            assert_eq!(store.dispatch_client_ctx.client_tracking, before);
        }
    }

    #[test]
    fn client_tracking_validates_option_matrix() {
        let mut store = Store::new();
        for (argv, expected) in [
            (
                vec![
                    b"CLIENT".to_vec(),
                    b"TRACKING".to_vec(),
                    b"ON".to_vec(),
                    b"PREFIX".to_vec(),
                    b"foo".to_vec(),
                ],
                CommandError::Custom(CLIENT_TRACKING_PREFIX_REQUIRES_BCAST.to_string()),
            ),
            (
                vec![
                    b"CLIENT".to_vec(),
                    b"TRACKING".to_vec(),
                    b"ON".to_vec(),
                    b"OPTIN".to_vec(),
                    b"OPTOUT".to_vec(),
                ],
                CommandError::Custom(CLIENT_TRACKING_OPTIN_OPTOUT_CONFLICT.to_string()),
            ),
            (
                vec![
                    b"CLIENT".to_vec(),
                    b"TRACKING".to_vec(),
                    b"ON".to_vec(),
                    b"BCAST".to_vec(),
                    b"OPTIN".to_vec(),
                ],
                CommandError::Custom(CLIENT_TRACKING_BCAST_OPT_CONFLICT.to_string()),
            ),
            (
                vec![
                    b"CLIENT".to_vec(),
                    b"TRACKING".to_vec(),
                    b"ON".to_vec(),
                    b"REDIRECT".to_vec(),
                    b"0".to_vec(),
                ],
                CommandError::Custom(CLIENT_TRACKING_REDIRECT_MISSING.to_string()),
            ),
        ] {
            let err = dispatch_argv(&argv, &mut store, 0).unwrap_err();
            assert_eq!(err, expected);
        }
    }

    #[test]
    fn client_caching_requires_optin_or_optout_modes() {
        // Upstream emits the mode-specific reply whether tracking
        // is disabled entirely or enabled in the wrong mode.
        // (br-frankenredis-w579)
        let mut store = Store::new();
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"CACHING".to_vec(), b"YES".to_vec()],
                &mut store,
                0
            )
            .unwrap_err(),
            CommandError::Custom(CLIENT_CACHING_YES_REQUIRES_OPTIN.to_string())
        );
        dispatch_argv(
            &[b"CLIENT".to_vec(), b"TRACKING".to_vec(), b"ON".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"CACHING".to_vec(), b"YES".to_vec()],
                &mut store,
                0
            )
            .unwrap_err(),
            CommandError::Custom(CLIENT_CACHING_YES_REQUIRES_OPTIN.to_string())
        );

        dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"TRACKING".to_vec(),
                b"ON".to_vec(),
                b"OPTIN".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"CACHING".to_vec(), b"YES".to_vec()],
                &mut store,
                0
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"CACHING".to_vec(), b"NO".to_vec()],
                &mut store,
                0
            )
            .unwrap_err(),
            CommandError::Custom(CLIENT_CACHING_NO_REQUIRES_OPTOUT.to_string())
        );

        assert_eq!(
            dispatch_argv(
                &[
                    b"CLIENT".to_vec(),
                    b"TRACKING".to_vec(),
                    b"ON".to_vec(),
                    b"OPTOUT".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom(CLIENT_TRACKING_OPT_SWITCH_REQUIRES_DISABLE.to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"CACHING".to_vec(), b"YES".to_vec()],
                &mut store,
                0
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        dispatch_argv(
            &[b"CLIENT".to_vec(), b"TRACKING".to_vec(), b"OFF".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"TRACKING".to_vec(),
                b"ON".to_vec(),
                b"OPTOUT".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"CACHING".to_vec(), b"NO".to_vec()],
                &mut store,
                0
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"CACHING".to_vec(), b"YES".to_vec()],
                &mut store,
                0
            )
            .unwrap_err(),
            CommandError::Custom(CLIENT_CACHING_YES_REQUIRES_OPTIN.to_string())
        );
    }

