    #[test]
    fn client_setname_validates_arity_and_characters() {
        let mut store = Store::new();
        let err =
            dispatch_argv(&[b"CLIENT".to_vec(), b"SETNAME".to_vec()], &mut store, 0).unwrap_err();
        assert_eq!(err, client_wrong_subcommand_arity("SETNAME"));

        let err = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"SETNAME".to_vec(),
                b"bad name".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err,
            CommandError::Custom(
                "ERR Client names cannot contain spaces, newlines or special characters."
                    .to_string()
            )
        );

        let out = dispatch_argv(
            &[b"CLIENT".to_vec(), b"SETNAME".to_vec(), b"bravo".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::SimpleString("OK".to_string()));
        assert_eq!(
            store.dispatch_client_ctx.client_name.as_deref(),
            Some(b"bravo".as_slice())
        );
    }

    #[test]
    fn function_and_script_parity_errors_match_vendored_redis() {
        let mut store = Store::new();
        let err = dispatch_argv(
            &[
                b"FUNCTION".to_vec(),
                b"LOAD".to_vec(),
                b"#!lua\nredis.register_function('f', function(keys, args) return 1 end)".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err.to_resp(),
            RespFrame::Error("ERR Library name was not given".to_string())
        );

        let kill = dispatch_argv(&[b"FUNCTION".to_vec(), b"KILL".to_vec()], &mut store, 0).unwrap();
        assert_eq!(
            kill,
            RespFrame::Error("NOTBUSY No scripts in execution right now.".to_string())
        );

        let cases = [
            (
                vec![b"FUNCTION".to_vec(), b"DELETE".to_vec()],
                "ERR wrong number of arguments for 'function|delete' command",
            ),
            (
                vec![b"FUNCTION".to_vec(), b"KILL".to_vec(), b"extra".to_vec()],
                "ERR wrong number of arguments for 'function|kill' command",
            ),
            (
                vec![b"FUNCTION".to_vec(), b"LOAD".to_vec()],
                "ERR wrong number of arguments for 'function|load' command",
            ),
            (
                vec![b"FUNCTION".to_vec(), b"RESTORE".to_vec()],
                "ERR wrong number of arguments for 'function|restore' command",
            ),
            (
                vec![
                    b"FUNCTION".to_vec(),
                    b"RESTORE".to_vec(),
                    b"payload".to_vec(),
                    b"FLUSH".to_vec(),
                    b"EXTRA".to_vec(),
                ],
                "ERR unknown subcommand or wrong number of arguments for 'RESTORE'. Try FUNCTION HELP.",
            ),
            (
                vec![b"SCRIPT".to_vec(), b"EXISTS".to_vec()],
                "ERR wrong number of arguments for 'script|exists' command",
            ),
            (
                vec![b"SCRIPT".to_vec(), b"LOAD".to_vec()],
                "ERR wrong number of arguments for 'script|load' command",
            ),
        ];
        for (argv, expected) in cases {
            let err = dispatch_argv(&argv, &mut store, 0).unwrap_err();
            assert_eq!(
                err.to_resp(),
                RespFrame::Error(expected.to_string()),
                "argv: {argv:?}"
            );
        }
    }

