    #[test]
    fn replication_admin_commands_reject_scripts_after_validation() {
        let mut store = Store::new();
        store.script_nesting_level = 1;

        let psync_arity = dispatch_argv(&[b"PSYNC".to_vec(), b"?".to_vec()], &mut store, 0)
            .expect_err("psync arity");
        assert_eq!(psync_arity, CommandError::WrongArity("PSYNC"));

        let psync = dispatch_argv(
            &[b"PSYNC".to_vec(), b"?".to_vec(), b"-1".to_vec()],
            &mut store,
            0,
        )
        .expect_err("psync noscript");
        assert_eq!(
            psync,
            CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string())
        );

        let replicaof_arity =
            dispatch_argv(&[b"REPLICAOF".to_vec()], &mut store, 0).expect_err("replicaof arity");
        assert_eq!(replicaof_arity, CommandError::WrongArity("REPLICAOF"));

        let replicaof_invalid = dispatch_argv(
            &[
                b"REPLICAOF".to_vec(),
                b"127.0.0.1".to_vec(),
                b"+6379".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("replicaof invalid port");
        assert_eq!(
            replicaof_invalid,
            CommandError::Custom("ERR Invalid master port".to_string())
        );

        let replicaof = dispatch_argv(
            &[b"REPLICAOF".to_vec(), b"NO".to_vec(), b"ONE".to_vec()],
            &mut store,
            0,
        )
        .expect_err("replicaof noscript");
        assert_eq!(
            replicaof,
            CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string())
        );

        let failover_syntax = dispatch_argv(
            &[b"FAILOVER".to_vec(), b"ABORT".to_vec(), b"ABORT".to_vec()],
            &mut store,
            0,
        )
        .expect_err("failover syntax");
        assert_eq!(failover_syntax, CommandError::SyntaxError);

        let failover_timeout = dispatch_argv(
            &[b"FAILOVER".to_vec(), b"TIMEOUT".to_vec(), b"0".to_vec()],
            &mut store,
            0,
        )
        .expect_err("failover timeout");
        assert_eq!(
            failover_timeout,
            CommandError::Custom("ERR FAILOVER timeout must be greater than 0".to_string())
        );

        let failover = dispatch_argv(&[b"FAILOVER".to_vec(), b"ABORT".to_vec()], &mut store, 0)
            .expect_err("failover noscript");
        assert_eq!(
            failover,
            CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string())
        );
    }

    fn read_test_frame(stream: &mut TcpStream, read_buf: &mut Vec<u8>) -> RespFrame {
        let parser_config = fr_protocol::ParserConfig::default();
        loop {
            match fr_protocol::parse_frame_with_config(read_buf, &parser_config) {
                Ok(parsed) => {
                    read_buf.drain(..parsed.consumed);
                    return parsed.frame;
                }
                Err(fr_protocol::RespParseError::Incomplete) => {}
                Err(err) => panic!("failed to parse test frame: {err:?}"), // ubs:ignore — AI triage
            }

            let mut chunk = [0u8; 4096];
            let n = stream.read(&mut chunk).expect("read test frame");
            assert_ne!(n, 0, "connection closed before frame completed");
            read_buf.extend_from_slice(&chunk[..n]);
        }
    }

    fn frame_to_bulk_argv(frame: RespFrame) -> Vec<Vec<u8>> {
        match frame {
            RespFrame::Array(Some(items)) => items
                .into_iter()
                .map(|item| match item {
                    RespFrame::BulkString(Some(bytes)) => bytes,
                    other => panic!("expected bulk string, got {other:?}"), // ubs:ignore — AI triage
                })
                .collect(),
            other => panic!("expected array frame, got {other:?}"), // ubs:ignore — AI triage
        }
    }

    struct ManagedRedis {
        child: std::process::Child,
    }

    impl Drop for ManagedRedis {
        fn drop(&mut self) {
            let _ = self.child.kill();
            let _ = self.child.wait();
        }
    }

    fn project_root() -> std::path::PathBuf {
        std::path::Path::new(env!("CARGO_MANIFEST_DIR"))
            .parent()
            .and_then(std::path::Path::parent)
            .expect("manifest has workspace root")
            .to_path_buf()
    }

    fn pick_free_port() -> u16 {
        let listener = std::net::TcpListener::bind(("127.0.0.1", 0)).expect("bind ephemeral port");
        listener.local_addr().expect("local addr").port()
    }

    fn wait_for_redis_cli(redis_cli: &std::path::Path, port: u16) -> bool {
        let port = port.to_string();
        for _ in 0..100 {
            if let Ok(output) = std::process::Command::new(redis_cli)
                .args(["-h", "127.0.0.1", "-p", port.as_str(), "--raw", "PING"])
                .output()
                && output.status.success()
                && output.stdout.starts_with(b"PONG")
            {
                return true;
            }
            std::thread::sleep(std::time::Duration::from_millis(20));
        }
        false
    }

    fn redis_cli_output(redis_cli: &std::path::Path, port: u16, argv: &[&str]) -> String {
        let port = port.to_string();
        let output = std::process::Command::new(redis_cli)
            .args(["-h", "127.0.0.1", "-p", port.as_str(), "--raw"])
            .args(argv)
            .output()
            .expect("run redis-cli");
        assert!(
            output.status.success(),
            "redis-cli {:?} failed: {}",
            argv,
            String::from_utf8_lossy(&output.stderr)
        );
        String::from_utf8(output.stdout).expect("redis-cli stdout is utf8")
    }

    fn redis_command(port: u16, argv: &[&[u8]]) -> RespFrame {
        let mut stream =
            TcpStream::connect(("127.0.0.1", port)).expect("connect vendored redis-server");
        let frame = RespFrame::Array(Some(
            argv.iter()
                .map(|arg| RespFrame::BulkString(Some((*arg).to_vec())))
                .collect(),
        ));
        stream
            .write_all(&frame.to_bytes())
            .expect("write redis command");
        let reply = read_test_frame(&mut stream, &mut Vec::new());
        let _ = stream.shutdown(std::net::Shutdown::Both);
        reply
    }

    fn redis_bulk_string(port: u16, argv: &[&[u8]]) -> Vec<u8> {
        match redis_command(port, argv) {
            RespFrame::BulkString(Some(bytes)) => bytes,
            other => panic!("expected Redis bulk string, got {other:?}"), // ubs:ignore - test assertion
        }
    }

    fn redis_array_bulk_strings(port: u16, argv: &[&[u8]]) -> Vec<Vec<u8>> {
        match redis_command(port, argv) {
            RespFrame::Array(Some(items)) => items
                .into_iter()
                .map(|item| match item {
                    RespFrame::BulkString(Some(bytes)) => bytes,
                    RespFrame::SimpleString(s) => s.into_bytes(),
                    RespFrame::Integer(i) => i.to_string().into_bytes(),
                    other => panic!("expected scalar Redis array item, got {other:?}"), // ubs:ignore - test assertion
                })
                .collect(),
            other => panic!("expected Redis array reply, got {other:?}"), // ubs:ignore - test assertion
        }
    }

    fn sorted_bytes(mut values: Vec<Vec<u8>>) -> Vec<Vec<u8>> {
        values.sort();
        values
    }

    fn sorted_bulk_pairs(flat: Vec<Vec<u8>>) -> Vec<(Vec<u8>, Vec<u8>)> {
        assert_eq!(flat.len() % 2, 0, "flat pair list must be even");
        let mut pairs: Vec<(Vec<u8>, Vec<u8>)> = flat
            .chunks_exact(2)
            .map(|pair| (pair[0].clone(), pair[1].clone()))
            .collect();
        pairs.sort();
        pairs
    }

